"""Cluster path layout — the source of truth for every file the
daemon reads or writes inside ``.meshkore/``.

Pure data, no I/O at construction, no threading. The lowest-coupling
module in the package; everything that needs to touch the cluster's
disk layout takes a ``Paths`` instance via constructor injection.

TLS constants live here too because the daemon's TLS bundle resolver
(``_find_tls_bundle``) sits next to ``daemon.py``, not under
``.meshkore/`` — but the filenames are part of the layout contract."""


from pathlib import Path

TLS_BUNDLE_NAME = "tls"
TLS_CERT_FILENAME = "fullchain.pem"
TLS_KEY_FILENAME = "privkey.pem"


class Paths:
    def __init__(self, root: Path):
        self.root = root.resolve()
        self.meshkore = self.root / ".meshkore"
        self.public = self.meshkore / "public"
        self.cluster_yaml = self.public / "cluster.yaml"
        # Standard §13 — deployment links registry. Optional file; the
        # registry treats a missing file as { version: 1, modules: [] }.
        self.links_yaml = self.public / "links.yaml"
        # Standard §14 — workflows (reusable multi-scope ordered runbooks;
        # renamed from "protocols" 2026-06-21 — "protocol" is reserved for
        # agent-comms standards A2A/MCP). Legacy `protocols_*` kept for the
        # back-compat read in WorkflowsRegistry until every cluster migrates.
        self.workflows_dir = self.meshkore / "workflows"
        self.workflows_log = self.workflows_dir / "log"
        self.protocols_dir = self.meshkore / "protocols"
        self.protocols_log = self.protocols_dir / "log"
        self.credentials = self.meshkore / "credentials"
        self.token_file = self.credentials / "portal-token"
        self.runtime = self.meshkore / ".runtime"
        self.pid_file = self.runtime / "daemon.pid"
        self.port_file = self.runtime / "port"
        self.timeline_dir = self.meshkore / "timeline"
        self.modules_dir = self.meshkore / "modules"
        self.docs_dir = self.meshkore / "docs"
        # Standard v14 §3.5 — project-wide INVARIANT context tree. The
        # canonical layout (overview/product/stack/architecture/
        # constraints + glossary + decisions/ + criteria/). Served
        # read-only over /context (tree) + /context/<path> (file body)
        # for the cockpit's Context tab. Distinct from docs/context.md
        # (the legacy single-file form predating v14).
        self.context_dir = self.meshkore / "context"
        # py-1.9.0 — daily narrative logs (operator/Claude prose, one
        # file per day). Served read-only over /log/<YYYY-MM-DD>.md +
        # listed under /log so the cockpit Diary tab can lazy-page.
        self.log_dir = self.meshkore / "log"
        # py-1.2.0 — where /self-update writes daemon.py + daemon.py.bak.
        self.scripts_dir = self.meshkore / "scripts"
        self.roadmap_dir = self.meshkore / "roadmap"
        self.state_json = self.roadmap_dir / "state.json"
        self.agents_dir = self.meshkore / "agents"
        self.initiatives = self.roadmap_dir / "initiatives"
        # Cron scheduler (D-CRON-01..05). State file is gitignored
        # under .meshkore/.runtime/; the logs dir holds per-run captures.
        self.crons_state_path = self.runtime / "crons.json"
        self.crons_logs_dir = self.runtime / "logs" / "cron"
        # py-1.12.19 — chat-turn queue (Standard v16). Per-conv FIFO
        # at `.meshkore/queues/<conv>.json`. Gitignored runtime artifact
        # — operator's typed pending instructions don't belong in git.
        self.queues_dir = self.meshkore / "queues"
        # py-1.12.21 — chat uploads. Image / file attachments sent with
        # /chat/dispatch land here under YYYY-MM-DD/ buckets so the
        # cockpit can render thumbnails. Gitignored (operator inputs
        # may contain anything); retention via cluster.yaml.uploads
        # (default 30 days), opportunistic GC on every upload.
        self.uploads_dir = self.meshkore / "uploads"
        # Initiative `agent-team` (ATM2) — the team roster. One markdown
        # file per member (frontmatter + init-prompt body) at
        # `.meshkore/team/<id>.md`. Committed with the repo (part of the
        # project's identity, no secrets); a chat conv becomes an INSTANCE
        # of a member (ATM10). Seeded with the canonical 8-member team on
        # first boot / init when the folder is missing or empty.
        self.team_dir = self.meshkore / "team"


# ── inlined from daemon/crypto_ed25519.py (DM3+ bundle) ─────────────────────────
"""crypto_ed25519.py — vendored pure-Python Ed25519 (sign + verify + keygen).

Why this exists (py-1.27.5). The daemon auto-updates by downloading a new
`daemon.py` from the CDN and re-exec'ing into it. Before this module the only
check was "does it parse + contain a DAEMON_VERSION marker" — so whoever
controls the CDN (or breaks TLS) could swap in arbitrary code that runs as the
operator. This adds CRYPTOGRAPHIC verification: every release is Ed25519-signed
with a private key that lives OFF the CDN (operator's machine only); the daemon
pins the PUBLIC key (constants.RELEASE_PUBKEY_HEX) and refuses to swap to a
build whose detached signature doesn't verify.

Stdlib-only by necessity — the daemon ships as a single zero-install `.py`, no
pip, so we can't use `cryptography`. This is the well-known public-domain
reference implementation (D. J. Bernstein et al., RFC 8032), with modular
exponentiation delegated to Python's built-in `pow(b, e, m)` for speed. Verify
runs once per update check (~0.1–0.5 s for two scalar-mults); fine for that.

NOT a general-purpose crypto library — it is constant-time-naive and only used
for release-signature verification of a public artifact. Do not repurpose it
for secrets handling.
"""


import hashlib

_b = 256
_q = 2**255 - 19
_L = 2**252 + 27742317777372353535851937790883648493


def _H(m: bytes) -> bytes:
    return hashlib.sha512(m).digest()


def _inv(x: int) -> int:
    return pow(x, _q - 2, _q)


_d = (-121665 * _inv(121666)) % _q
_I = pow(2, (_q - 1) // 4, _q)


def _xrecover(y: int) -> int:
    xx = (y * y - 1) * _inv(_d * y * y + 1)
    x = pow(xx, (_q + 3) // 8, _q)
    if (x * x - xx) % _q != 0:
        x = (x * _I) % _q
    if x % 2 != 0:
        x = _q - x
    return x


_By = (4 * _inv(5)) % _q
_Bx = _xrecover(_By)
_B = [_Bx % _q, _By % _q]


def _edwards(P, Q):
    x1, y1 = P
    x2, y2 = Q
    x3 = (x1 * y2 + x2 * y1) * _inv(1 + _d * x1 * x2 * y1 * y2)
    y3 = (y1 * y2 + x1 * x2) * _inv(1 - _d * x1 * x2 * y1 * y2)
    return [x3 % _q, y3 % _q]


def _scalarmult(P, e: int):
    # Iterative double-and-add (avoids deep recursion on a 253-bit scalar).
    Q = [0, 1]
    bits = []
    while e > 0:
        bits.append(e & 1)
        e >>= 1
    for bit in reversed(bits):
        Q = _edwards(Q, Q)
        if bit:
            Q = _edwards(Q, P)
    return Q


def _encodeint(y: int) -> bytes:
    return y.to_bytes(_b // 8, "little")


def _encodepoint(P) -> bytes:
    x, y = P
    val = y | ((x & 1) << (_b - 1))
    return val.to_bytes(_b // 8, "little")


def _bit(h: bytes, i: int) -> int:
    return (h[i // 8] >> (i % 8)) & 1


def _Hint(m: bytes) -> int:
    h = _H(m)
    return sum(2**i * _bit(h, i) for i in range(2 * _b))


def _secret_scalar(seed: bytes) -> int:
    h = _H(seed)
    return 2 ** (_b - 2) + sum(2**i * _bit(h, i) for i in range(3, _b - 2))


def ed25519_publickey(seed: bytes) -> bytes:
    """32-byte Ed25519 public key from a 32-byte seed (private key)."""
    if len(seed) != 32:
        raise ValueError("seed must be 32 bytes")
    A = _scalarmult(_B, _secret_scalar(seed))
    return _encodepoint(A)


def ed25519_sign(msg: bytes, seed: bytes, pub: bytes) -> bytes:
    """64-byte detached Ed25519 signature over msg."""
    h = _H(seed)
    a = _secret_scalar(seed)
    r = _Hint(h[_b // 8 : _b // 4] + msg)
    R = _scalarmult(_B, r)
    S = (r + _Hint(_encodepoint(R) + pub + msg) * a) % _L
    return _encodepoint(R) + _encodeint(S)


def _isoncurve(P) -> bool:
    x, y = P
    return (-x * x + y * y - 1 - _d * x * x * y * y) % _q == 0


def _decodeint(s: bytes) -> int:
    return int.from_bytes(s, "little")


def _decodepoint(s: bytes):
    y = int.from_bytes(s, "little") & ((1 << (_b - 1)) - 1)
    x = _xrecover(y)
    if x & 1 != _bit(s, _b - 1):
        x = _q - x
    P = [x, y]
    if not _isoncurve(P):
        raise ValueError("point not on curve")
    return P


def ed25519_verify(pub: bytes, msg: bytes, sig: bytes) -> bool:
    """True iff `sig` is a valid Ed25519 signature of `msg` under `pub`.
    Never raises — any malformed input returns False."""
    try:
        if len(sig) != 64 or len(pub) != 32:
            return False
        R = _decodepoint(sig[: _b // 8])
        A = _decodepoint(pub)
        S = _decodeint(sig[_b // 8 : _b // 4])
        h = _Hint(_encodepoint(R) + pub + msg)
        return _scalarmult(_B, S) == _edwards(R, _scalarmult(A, h))
    except Exception:
        return False


# ── inlined from daemon/fsatomic.py (DM3+ bundle) ─────────────────────────
"""fsatomic.py — crash-safe atomic file writes (Phase E3 DRY leaf).

Every on-disk JSON/YAML/markdown the daemon persists uses the same dance:
write a sibling ``<name>.tmp``, (optionally) fsync, then ``os.replace`` —
atomic on POSIX, so a crash mid-write leaves the OLD file intact, never a
truncated one that a later read silently parses as empty. That idiom was
copy-pasted across ~9 modules; this leaf is the single source of truth.

Leaf module: stdlib only, no daemon imports. Callers pass the exact JSON
flags they need (``sort_keys`` changes the bytes; ``fsync`` adds durability
without changing content) so the swap is byte-for-byte behaviour-preserving."""


import json
import os
from pathlib import Path
from typing import Any


def atomic_write_text(path: Path, text: str, *, fsync: bool = False) -> None:
    """Write ``text`` to ``path`` atomically via a sibling ``.tmp`` + replace.

    ``fsync=True`` flushes the kernel buffer to disk before the rename (use
    for state that must survive a hard crash — chat queues, archives)."""
    tmp = path.with_suffix(path.suffix + ".tmp")
    with open(tmp, "w", encoding="utf-8") as fh:
        fh.write(text)
        if fsync:
            fh.flush()
            os.fsync(fh.fileno())
    os.replace(tmp, path)


def atomic_write_json(
    path: Path,
    obj: Any,
    *,
    indent: int = 2,
    sort_keys: bool = False,
    fsync: bool = False,
    trailing_newline: bool = False,
) -> None:
    """``json.dumps(obj, …)`` then :func:`atomic_write_text`. Flags mirror the
    call sites so output stays byte-identical to the hand-rolled versions."""
    text = json.dumps(obj, indent=indent, sort_keys=sort_keys)
    if trailing_newline:
        text += "\n"
    atomic_write_text(path, text, fsync=fsync)


# ── inlined from daemon/timeutil.py (DM3+ bundle) ─────────────────────────
"""timeutil.py — UTC ISO-8601 timestamp helpers.

Extracted from utils.py (daemon-architecture-v2 Phase 3d). Verbatim move;
imported back where used."""


from datetime import datetime, timezone


def _iso_now() -> str:
    return (
        datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.")
        + f"{datetime.now(timezone.utc).microsecond // 1000:03d}Z"
    )


def _iso_at(epoch_secs: int) -> str:
    """ISO-8601 UTC for a given epoch — used for pause expiry stamps
    (py-1.10.26). Cheap; no ms component (we only care about the
    minute granularity for rate-limit cooldowns)."""
    return datetime.fromtimestamp(epoch_secs, timezone.utc).strftime(
        "%Y-%m-%dT%H:%M:%SZ"
    )


# ── inlined from daemon/yamlparse.py (DM3+ bundle) ─────────────────────────
"""yamlparse.py — tiny YAML + frontmatter parser.

Extracted from utils.py (daemon-architecture-v2 Phase 3d). Verbatim move;
imported back where used."""


import re
from typing import Any, Dict, List, Tuple

_FM_RE = re.compile(r"^---\s*\n(.*?)\n---\s*\n", re.DOTALL)


def parse_simple_yaml(text: str) -> Dict[str, Any]:
    """Parses a YAML subset sufficient for our cluster.yaml + frontmatter
    blocks. Supports scalars, dicts, lists, list-of-dicts, and inline
    list scalars (`tags: [a, b]`). NOT a general YAML parser — fail
    loudly for shapes we don't handle."""
    out: Dict[str, Any] = {}
    # Stack entry: (indent, container, key_in_parent, parent_ref_or_None)
    stack: List[Tuple[int, Any, str, Any]] = [(-1, out, "", None)]
    lines = text.splitlines()
    i = 0
    while i < len(lines):
        raw = lines[i]
        line = raw.rstrip()
        stripped = line.lstrip()
        if not stripped or stripped.startswith("#"):
            i += 1
            continue
        indent = len(line) - len(stripped)
        while stack and indent <= stack[-1][0] and len(stack) > 1:
            stack.pop()
        parent = stack[-1][1]

        if stripped.startswith("- "):
            value = stripped[2:].strip()
            # Promote: if the current container is an empty dict that was
            # just created as a nested holder for some key, convert it to
            # a list in the grandparent — we now know the value is a list.
            if isinstance(parent, dict) and not parent:
                key = stack[-1][2]
                gp = stack[-1][3]
                if key and isinstance(gp, dict) and gp.get(key) is parent:
                    new_list: List[Any] = []
                    gp[key] = new_list
                    stack[-1] = (stack[-1][0], new_list, key, gp)
                    parent = new_list
            if isinstance(parent, list):
                # Two shapes:
                #   "- value"               → scalar item
                #   "- key: val\n  key2: …" → dict item (continues below)
                if ":" in value:
                    item: Dict[str, Any] = {}
                    parent.append(item)
                    # Treat the inline "key: val" as the first dict entry
                    k2, _, v2 = value.partition(":")
                    k2 = k2.strip()
                    v2 = v2.strip()
                    if v2:
                        item[k2] = _coerce(_strip_inline_comment(v2))
                        stack.append((indent, item, "", parent))
                    else:
                        # Nested key with no value yet
                        nested: Dict[str, Any] = {}
                        item[k2] = nested
                        stack.append((indent, item, "", parent))
                        stack.append((indent + 2, nested, k2, item))
                else:
                    parent.append(
                        _coerce(_strip_inline_comment(value)) if value else None
                    )

        elif ":" in stripped:
            key, _, val = stripped.partition(":")
            key = key.strip()
            val = _strip_inline_comment(val.strip())
            if val == "":
                nxt: Dict[str, Any] = {}
                if isinstance(parent, dict):
                    parent[key] = nxt
                stack.append((indent, nxt, key, parent))
            elif val.startswith("[") and val.endswith("]"):
                # Inline list scalar: [a, b, "c d"]
                inner = val[1:-1].strip()
                items = (
                    [_coerce(x.strip()) for x in _split_top_level_commas(inner)]
                    if inner
                    else []
                )
                if isinstance(parent, dict):
                    parent[key] = items
            else:
                if isinstance(parent, dict):
                    parent[key] = _coerce(val)
        i += 1
    return out


def _strip_inline_comment(v: str) -> str:
    return re.sub(r"\s+#.*$", "", v)


def _split_top_level_commas(s: str) -> List[str]:
    out, buf, depth, in_str = [], "", 0, None
    for ch in s:
        if in_str:
            buf += ch
            if ch == in_str:
                in_str = None
            continue
        if ch in ('"', "'"):
            in_str = ch
            buf += ch
            continue
        if ch == "," and depth == 0:
            out.append(buf)
            buf = ""
            continue
        if ch in "[{":
            depth += 1
        elif ch in "]}":
            depth -= 1
        buf += ch
    if buf.strip():
        out.append(buf)
    return out


def _coerce(v: str) -> Any:
    s = v.strip()
    if not s:
        return ""
    if (s.startswith('"') and s.endswith('"')) or (
        s.startswith("'") and s.endswith("'")
    ):
        return s[1:-1]
    if s.lower() in ("true", "yes"):
        return True
    if s.lower() in ("false", "no"):
        return False
    if s.lower() in ("null", "~"):
        return None
    try:
        return int(s)
    except ValueError:
        pass
    try:
        return float(s)
    except ValueError:
        pass
    return s


def parse_frontmatter(text: str) -> Dict[str, Any]:
    m = _FM_RE.match(text)
    if not m:
        return {}
    return parse_simple_yaml(m.group(1))


# ── inlined from daemon/timeline.py (DM3+ bundle) ─────────────────────────
"""timeline.py — timeline JSONL read/append helpers.

Extracted from utils.py (daemon-architecture-v2 Phase 3d). Verbatim move;
imported back where used."""


import json
import os
from typing import Any, Dict, List



def _iter_timeline_files(paths: "Paths") -> List[Any]:
    """All timeline files (jsonl + jsonl.gz from rotation)."""
    if not paths.timeline_dir.exists():
        return []
    files = list(paths.timeline_dir.glob("*.jsonl"))
    files.extend(paths.timeline_dir.glob("*.jsonl.gz"))
    # Also look in the archive subdir produced by rotation.
    archive_dir = paths.timeline_dir / "archive"
    if archive_dir.exists():
        files.extend(archive_dir.glob("*.jsonl"))
        files.extend(archive_dir.glob("*.jsonl.gz"))
    return files


def _read_timeline_file(path: Any) -> List[Dict[str, Any]]:
    """Parse one timeline file (jsonl or jsonl.gz) → list of events.
    Never raises; bad lines / unreadable files yield empty list."""
    try:
        if str(path).endswith(".gz"):
            import gzip

            with gzip.open(path, "rt", encoding="utf-8", errors="replace") as fh:
                lines = fh.read().splitlines()
        else:
            lines = path.read_text(errors="replace").splitlines()
    except OSError:
        return []
    out: List[Dict[str, Any]] = []
    for line in lines:
        try:
            out.append(json.loads(line))
        except json.JSONDecodeError:
            continue
    return out


def _append_timeline(paths: "Paths", event: Dict[str, Any]) -> Dict[str, Any]:
    """Append one JSON-line event to today's timeline file.
    Returns the event enriched with `ts` if it wasn't already set.

    py-1.5.0 — atomic append. The line is rendered fully in memory,
    then written + flushed + fsync'd in a single open/close cycle so
    a daemon crash mid-write can't leave a half-written line in the
    jsonl. We rely on the OS guarantee that `write()` is atomic for
    buffers < PIPE_BUF (~4KB on most systems); for larger events
    (very long assistant.final replies) we still get atomicity at the
    page-cache level under POSIX. The added fsync forces durability
    so we don't lose events on a power cut either."""
    paths.timeline_dir.mkdir(parents=True, exist_ok=True)
    if "ts" not in event:
        event = {**event, "ts": _iso_now()}
    date = event["ts"][:10]
    f = paths.timeline_dir / f"{date}.jsonl"
    payload = json.dumps(event, separators=(",", ":")) + "\n"
    encoded = payload.encode("utf-8")
    # Open with O_APPEND so concurrent writers (the StateManager poll
    # loop + ChatRunner reader threads) interleave at line boundaries
    # rather than overwrite each other. O_APPEND is atomic per write()
    # on POSIX for any size up to PIPE_BUF; for larger writes (a multi-
    # KB assistant.final) the worst case is interleaved bytes, but the
    # daemon's writers never race on the same line. Single line per
    # write() call preserves jsonl integrity.
    fd = os.open(f, os.O_WRONLY | os.O_APPEND | os.O_CREAT, 0o644)
    try:
        os.write(fd, encoded)
        try:
            os.fsync(fd)
        except OSError:
            pass  # best-effort durability
    finally:
        os.close(fd)
    return event


# ── inlined from daemon/utils.py (DM3+ bundle) ─────────────────────────
"""Shared utilities — time helpers, daemon logger, debug stream,
timeline-file iterators.

Imported by every sibling module that needs ``_log`` / ``_iso_now`` /
``_debug_emit``. Replaces the per-module shadow-stub pattern used in
DM3-DM6: now every module gets the REAL helpers from a single source,
and the bundle's late-binding global lookup keeps working unchanged
(``_log`` resolved from this module's globals, which become part of
the bundle's flat namespace).

Stdlib-only (constraint from ``python-daemon`` initiative). Depends on
``paths.py`` for ``_iter_timeline_files`` only; everything else is
self-contained."""


import socket  # noqa: F401 — re-exported for callers that prefer `utils.socket`
from pathlib import Path
from typing import TYPE_CHECKING, Any, Dict, Optional, Tuple


# Re-exports so existing `from utils import X` call sites are unchanged after the
# Phase-3d split (time→timeutil, parse+_FM_RE→yamlparse, timeline→timeline). The
# leaves are import-light (timeutil/yamlparse self-contained; timeline→timeutil
# only), so utils→leaf is one-way — no cycle.

# ── time helpers ──────────────────────────────────────────────────────


# ── debug stream singleton + daemon log ──────────────────────────────
# Module-level singleton so `_log()` and any free function can emit
# without threading a `daemon` ref through every call site. Set by
# Daemon.serve_forever during boot (see daemon.py).

_DEBUG_LOG: Optional["DebugLog"] = None


def set_debug_log(log: Optional["DebugLog"]) -> None:
    """Daemon boot calls this to wire the singleton. Sibling modules
    don't need to know which module owns the global — they just call
    ``debug_enabled()`` or ``_debug_emit(...)``."""
    global _DEBUG_LOG
    _DEBUG_LOG = log


def debug_enabled() -> bool:
    return _DEBUG_LOG is not None


def get_debug_log() -> Optional["DebugLog"]:
    """Live ref for callers that need to call methods on the singleton
    (``DebugLog.tail``, ``DebugLog.emit``). Returns ``None`` when the
    debug stream is disabled."""
    return _DEBUG_LOG


def _log(msg: str) -> None:
    print(f"[meshcore-py {_iso_now()}] {msg}", flush=True)
    # py-1.10.17 — mirror every daemon log line into the debug stream
    # so a single tail covers the unstructured prose + the structured
    # event hooks (architect-wake, chat-dispatch, …) below.
    if _DEBUG_LOG is not None:
        try:
            _DEBUG_LOG.emit(tag="log", lvl="info", msg=msg, src="daemon")
        except Exception:
            # Debug stream failures must never block the program.
            pass


_REDACT_KEYS = {
    "token",
    "authorization",
    "bearer",
    "api_key",
    "apikey",
    "secret",
    "password",
}


def _debug_redact(data: Any) -> Any:
    """Best-effort scrub of token-like values in arbitrary payloads."""
    if isinstance(data, dict):
        out: Dict[str, Any] = {}
        for k, v in data.items():
            if str(k).lower() in _REDACT_KEYS:
                out[k] = "<redacted>"
            else:
                out[k] = _debug_redact(v)
        return out
    if isinstance(data, list):
        return [_debug_redact(x) for x in data]
    if isinstance(data, str) and len(data) > 24 and data.startswith("Bearer "):
        return "Bearer <redacted>"
    return data


def _debug_emit(
    tag: str,
    *,
    msg: str = "",
    lvl: str = "info",
    src: str = "daemon",
    conv: Optional[str] = None,
    agent_id: Optional[str] = None,
    data: Optional[Dict[str, Any]] = None,
) -> None:
    """Convenience: skip the `if _DEBUG_LOG is not None:` dance at
    every emit site. No-op when the daemon hasn't initialised yet OR
    when the operator opted out via `cluster.yaml.debug.enabled: false`
    (py-1.10.21)."""
    if _DEBUG_LOG is None:
        return
    try:
        _DEBUG_LOG.emit(
            tag=tag,
            msg=msg,
            lvl=lvl,
            src=src,
            conv=conv,
            agent_id=agent_id,
            data=data,
        )
    except Exception:
        pass


def _debug_enabled(cluster: Any) -> bool:
    """Read `cluster.yaml.debug.enabled` (default `True`). Falsy disables
    DebugLog initialisation entirely — no file written, /debug/tail
    returns empty, /debug/log accepts but drops. py-1.10.21. Note the
    default is ON for MeshKore native development; downstream clusters
    that want zero disk footprint flip it to false."""
    try:
        block = cluster.data.get("debug") if isinstance(cluster.data, dict) else None
        if not isinstance(block, dict):
            return True
        v = block.get("enabled")
        if v is None:
            return True
        if isinstance(v, bool):
            return v
        return str(v).strip().lower() not in ("0", "false", "no", "off")
    except Exception:
        return True


