# ── inlined from daemon/fsread.py (DM3+ bundle) ─────────────────────────
"""fsread.py — extracted from readapi.py (daemon-architecture-v2 Phase 3d).

FsReadMixin: methods moved VERBATIM out of QueryMixin; Daemon inherits both so
every self.* resolves on the combined instance -> byte-identical."""


from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional



class FsReadMixin:
    def initiative_activity(self, initiative_id: str) -> Dict[str, Any]:
        """py-1.9.3 — Walk git log for commits referencing this initiative.
        Returns at most 50 of the most recent matching commits, each with
        the files it touched (`git diff-tree --no-commit-id --name-only -r`).
        Matching is plain substring on subject + body so operators can
        reference an initiative however they like ("[I-cron-dashboard]",
        "for cron-dashboard", etc.) — no rigid trailer schema.

        Bounded by 1000 commits scanned + a hard timeout per git call so
        a 50k-commit repo doesn't melt the daemon. Failures (no git, bad
        repo, timeout) degrade to an empty payload + an explanatory
        `error` field; the cockpit just shows "no activity yet".
        """
        out: Dict[str, Any] = {
            "initiative_id": initiative_id,
            "commits": [],
            "generated_at": _iso_now(),
        }
        if not isinstance(initiative_id, str) or not initiative_id.strip():
            out["error"] = "invalid initiative id"
            return out
        iid = initiative_id.strip()

        import subprocess as _sp

        root = self.paths.root

        # py-1.9.3 — Multi-repo workspaces (meshkore-style: webapp/,
        # architect/, .meshkore/ each a separate git repo at depth 1)
        # AND single-repo projects (typical ikamiro-style) both work.
        # Find every depth ≤ 1 directory that owns a `.git` and scan
        # each one. The commit row carries a `repo` field so the
        # cockpit can disambiguate when two repos both reference the
        # same initiative id.
        repo_dirs: List[Path] = []
        if (root / ".git").exists():
            repo_dirs.append(root)
        else:
            try:
                for child in sorted(root.iterdir()):
                    if not child.is_dir() or child.name.startswith("."):
                        continue
                    if (child / ".git").exists():
                        repo_dirs.append(child)
            except OSError:
                pass

        if not repo_dirs:
            out["error"] = "no git repos found at project root or depth-1"
            return out

        def git_in(cwd: Path, *args: str, timeout: float = 4.0) -> Optional[str]:
            try:
                r = _sp.run(
                    ["git", "-C", str(cwd), *args],
                    capture_output=True,
                    text=True,
                    timeout=timeout,
                )
                if r.returncode != 0:
                    return None
                return r.stdout
            except (_sp.TimeoutExpired, FileNotFoundError, OSError):
                return None

        commits: List[Dict[str, Any]] = []
        for repo_dir in repo_dirs:
            repo_label = repo_dir.name if repo_dir != root else "(root)"
            raw = git_in(
                repo_dir,
                "log",
                "--max-count=1000",
                "--grep",
                iid,
                "-i",
                "--pretty=format:%H%x09%h%x09%aI%x09%an%x09%s",
                timeout=6.0,
            )
            if raw is None:
                continue
            for line in raw.splitlines():
                if not line.strip():
                    continue
                parts = line.split("\t", 4)
                if len(parts) != 5:
                    continue
                sha, short, ts, author, subject = parts
                files_raw = (
                    git_in(
                        repo_dir,
                        "diff-tree",
                        "--no-commit-id",
                        "--name-only",
                        "-r",
                        sha,
                        timeout=3.0,
                    )
                    or ""
                )
                files = [ln.strip() for ln in files_raw.splitlines() if ln.strip()]
                commits.append(
                    {
                        "repo": repo_label,
                        "sha": sha,
                        "short_sha": short,
                        "ts": ts,
                        "author": author,
                        "subject": subject,
                        "files": files[:200],
                        "files_truncated": len(files) > 200,
                    }
                )
                if len(commits) >= 50:
                    break
            if len(commits) >= 50:
                break

        # Newest first across repos (each repo's slice already comes
        # newest-first from git log, but interleaved across repos
        # needs an explicit ts sort).
        commits.sort(key=lambda c: c.get("ts") or "", reverse=True)
        out["commits"] = commits[:50]
        return out

    def context_tree(self) -> Dict[str, Any]:
        """py-1.14.1 — Standard v14 §3.5 project context tree.

        Walks `.meshkore/context/` and returns the nested folder/file
        shape the cockpit's Context tab renders: per-file `title`
        (frontmatter `title`, falling back to a humanized filename),
        `updated` + `status` (frontmatter), word count, and an
        `over_cap` flag against the §3.5 brevity caps. Tree-level the
        response carries `total_words`, `token_estimate` (~1.5 tokens /
        word), the 4500-token budget, an `over_budget` flag, and a
        `warnings` list (per-file over-cap notes + total-over-budget).

        File bodies are NOT inlined — the cockpit lazy-fetches each on
        selection via `/context/<path>`. Returns `exists: False` with
        an empty tree when no `.meshkore/context/` directory is present
        (e.g. a freshly bootstrapped cluster) so the cockpit can render
        its empty-state hint instead of an error.

        Path traversal is structurally impossible here — we only ever
        `iterdir()` inside `context_dir`; `path` values are relative to
        that root and consumed by `/context/<path>` which re-validates.
        """
        root = self.paths.context_dir
        warnings: List[str] = []

        def humanize(name: str) -> str:
            stem = name[:-3] if name.endswith(".md") else name
            return stem.replace("-", " ").replace("_", " ").strip().capitalize()

        def word_count(text: str) -> int:
            # Count words in the body only (frontmatter excluded) so the
            # cap reflects prose, not YAML keys.
            _fm, body = _split_frontmatter(text)
            return len(body.split())

        def build_file(fp: "Path", rel: str, cap: Optional[int]):
            title = humanize(fp.name)
            updated: Optional[str] = None
            status: Optional[str] = None
            words = 0
            try:
                text = fp.read_text(encoding="utf-8", errors="replace")
                fm = parse_frontmatter(text)
                if isinstance(fm.get("title"), str) and fm["title"].strip():
                    title = fm["title"].strip()
                if isinstance(fm.get("updated"), str):
                    updated = fm["updated"].strip()
                elif fm.get("updated") is not None:
                    updated = str(fm["updated"])
                if isinstance(fm.get("status"), str) and fm["status"].strip():
                    status = fm["status"].strip()
                words = word_count(text)
            except OSError:
                pass
            over_cap = cap is not None and words > cap
            if over_cap:
                warnings.append(f"{rel}: {words}w over the {cap}w cap")
            node: Dict[str, Any] = {
                "kind": "file",
                "name": fp.name,
                "path": rel,
                "title": title,
                "words": words,
                "over_cap": over_cap,
            }
            if updated:
                node["updated"] = updated
            if status:
                node["status"] = status
            return node, words

        def cap_for(rel: str, name: str, in_folder: bool) -> Optional[int]:
            if in_folder:
                # README.md is an index, exempt; other entries cap at 100.
                return None if name == "README.md" else self.CONTEXT_FOLDER_ENTRY_CAP
            return self.CONTEXT_WORD_CAPS.get(name)

        total_words = 0

        def build_dir(dp: "Path", rel_prefix: str, in_folder: bool):
            nonlocal total_words
            children: List[Dict[str, Any]] = []
            try:
                entries = sorted(dp.iterdir(), key=lambda e: e.name)
            except OSError:
                return children
            # Files first (alpha), then sub-dirs — but keep README.md at
            # the top of a folder so the cockpit's "click dir → README"
            # affordance lands on the index.
            files = [
                e
                for e in entries
                if e.is_file()
                and e.suffix.lower() == ".md"
                and not e.name.startswith(".")
            ]
            dirs = [e for e in entries if e.is_dir() and not e.name.startswith(".")]
            files.sort(key=lambda e: (e.name != "README.md", e.name))
            for f in files:
                rel = f"{rel_prefix}{f.name}"
                node, words = build_file(f, rel, cap_for(rel, f.name, in_folder))
                total_words += words
                children.append(node)
            for d in dirs:
                rel = f"{rel_prefix}{d.name}"
                sub = build_dir(d, f"{rel}/", in_folder=True)
                children.append(
                    {
                        "kind": "dir",
                        "name": d.name,
                        "path": rel,
                        "title": humanize(d.name),
                        "children": sub,
                    }
                )
            return children

        if not root.is_dir():
            return {
                "exists": False,
                "root": ".meshkore/context",
                "total_words": 0,
                "token_estimate": 0,
                "budget_tokens": self.CONTEXT_BUDGET_TOKENS,
                "over_budget": False,
                "warnings": [],
                "tree": [],
            }

        tree = build_dir(root, "", in_folder=False)
        token_estimate = int(round(total_words * 1.5))
        over_budget = token_estimate > self.CONTEXT_BUDGET_TOKENS
        if over_budget:
            warnings.append(
                f"context is {token_estimate} tokens — over the "
                f"{self.CONTEXT_BUDGET_TOKENS}-token budget (§3.5)"
            )
        return {
            "exists": True,
            "root": ".meshkore/context",
            "total_words": total_words,
            "token_estimate": token_estimate,
            "budget_tokens": self.CONTEXT_BUDGET_TOKENS,
            "over_budget": over_budget,
            "warnings": warnings,
            "tree": tree,
        }

    # ── knowledge-tree-unified KT4 — unified knowledge tree ──────────
    def _knowledge_manifest(self):
        """Parse `.meshkore/context/_index.yaml` → (version, [valid nodes]).

        Returns (None, []) when no manifest is present so callers can fall
        back to the empty state. Nodes missing id/title are dropped.
        """
        mf = self.paths.context_dir / "_index.yaml"
        if not mf.is_file():
            return None, []
        try:

            data = parse_simple_yaml(mf.read_text(encoding="utf-8", errors="replace"))
        except Exception:
            return None, []
        nodes = data.get("nodes")
        if not isinstance(nodes, list):
            return data.get("version"), []
        valid = [
            n for n in nodes if isinstance(n, dict) and n.get("id") and n.get("title")
        ]
        return data.get("version"), valid

    def _knowledge_src_path(self, src: str) -> Optional["Path"]:
        """Resolve a manifest `src` to a real file under `.meshkore/`, or
        None if it escapes the root or does not exist. Path traversal
        (`../`) can never leave `.meshkore/`."""
        if not isinstance(src, str) or not src.strip():
            return None
        meshroot = self.paths.meshkore
        fp = (meshroot / src.strip()).resolve()
        try:
            if not str(fp).startswith(str(meshroot.resolve())):
                return None
        except OSError:
            return None
        return fp if fp.is_file() else None

    def knowledge_tree(self) -> Dict[str, Any]:
        """knowledge-tree-unified KT4 — the unified knowledge tree (overlay).

        Reads `.meshkore/context/_index.yaml` (a FLAT list of concept nodes,
        each optionally pointing `src` at a real file under context/, docs/
        or modules/), resolves each node's body metadata, and rebuilds the
        hierarchy from id/parent. NO file is moved — this is a VIEW.

        Per node: id, title, desc, load (pinned|skeleton|on-demand), src,
        feeds, words, updated, has_body, children[]. Tree-level: spawn_tokens
        (the skeleton map + pinned bodies the daemon injects at every spawn),
        skeleton_tokens, pinned_tokens, budget_tokens, over_budget, warnings.

        Falls back to `exists: False` when no manifest is present so the
        cockpit can render its empty-state hint instead of an error.
        """
        version, raw = self._knowledge_manifest()
        if version is None and not raw:
            return {
                "exists": False,
                "root": ".meshkore/context/_index.yaml",
                "spawn_tokens": 0,
                "budget_tokens": self.CONTEXT_BUDGET_TOKENS,
                "over_budget": False,
                "warnings": [],
                "tree": [],
            }

        warnings: List[str] = []
        loads = ("pinned", "skeleton", "on-demand")
        by_id: Dict[str, Dict[str, Any]] = {}
        skeleton_words = 0
        pinned_words = 0

        for n in raw:
            nid = str(n["id"]).strip()
            title = str(n["title"]).strip()
            desc = str(n.get("desc") or "").strip()
            load = str(n.get("load") or "skeleton").strip()
            if load not in loads:
                warnings.append(f"{nid}: unknown load '{load}' → skeleton")
                load = "skeleton"
            words = 0
            updated: Optional[str] = None
            has_body = False
            src = n.get("src")
            if isinstance(src, str) and src.strip():
                fp = self._knowledge_src_path(src)
                if fp is None:
                    warnings.append(
                        f"{nid}: src '{src.strip()}' missing/escapes — dropped"
                    )
                    src = None
                else:
                    has_body = True
                    try:
                        text = fp.read_text(encoding="utf-8", errors="replace")
                        fm = parse_frontmatter(text)
                        if isinstance(fm.get("updated"), str):
                            updated = fm["updated"].strip()
                        _fm, body = _split_frontmatter(text)
                        words = len(body.split())
                    except OSError:
                        pass
            else:
                src = None
            # every node contributes its skeleton line (title + desc) to the
            # spawn map; only pinned nodes contribute their body.
            skeleton_words += len((title + " " + desc).split())
            if load == "pinned" and has_body:
                pinned_words += words
            node: Dict[str, Any] = {
                "id": nid,
                "title": title,
                "desc": desc,
                "load": load,
                "words": words,
                "has_body": has_body,
                "children": [],
            }
            if src:
                node["src"] = src.strip()
            if updated:
                node["updated"] = updated
            if n.get("feeds"):
                node["feeds"] = str(n["feeds"]).strip()
            node["_parent"] = str(n.get("parent")).strip() if n.get("parent") else None
            by_id[nid] = node

        # rebuild hierarchy preserving manifest order
        roots: List[Dict[str, Any]] = []
        for n in raw:
            node = by_id.get(str(n["id"]).strip())
            if not node:
                continue
            pid = node.pop("_parent", None)
            if pid and pid in by_id:
                by_id[pid]["children"].append(node)
            else:
                if pid:
                    warnings.append(f"{node['id']}: parent '{pid}' not found → root")
                roots.append(node)

        skeleton_tokens = int(round(skeleton_words * 1.5))
        pinned_tokens = int(round(pinned_words * 1.5))
        spawn_tokens = skeleton_tokens + pinned_tokens
        over_budget = spawn_tokens > self.CONTEXT_BUDGET_TOKENS
        if over_budget:
            warnings.append(
                f"spawn payload {spawn_tokens} tok over the "
                f"{self.CONTEXT_BUDGET_TOKENS}-token budget (§3.5)"
            )
        return {
            "exists": True,
            "root": ".meshkore/context/_index.yaml",
            "version": version,
            "spawn_tokens": spawn_tokens,
            "skeleton_tokens": skeleton_tokens,
            "pinned_tokens": pinned_tokens,
            "budget_tokens": self.CONTEXT_BUDGET_TOKENS,
            "over_budget": over_budget,
            "warnings": warnings,
            "tree": roots,
        }

    def knowledge_node(self, node_id: str) -> Dict[str, Any]:
        """knowledge-tree-unified KT4 — a single node's processed body.

        Serves `GET /knowledge/<id>`: the body markdown (frontmatter
        stripped) of the file the manifest node points at. Pointer nodes
        (no `src`) return `has_body: False` with their desc.
        """
        _version, raw = self._knowledge_manifest()
        nid = (node_id or "").strip()
        for n in raw:
            if str(n.get("id")).strip() != nid:
                continue
            base = {
                "id": nid,
                "title": str(n.get("title") or "").strip(),
                "desc": str(n.get("desc") or "").strip(),
            }
            src = n.get("src")
            fp = self._knowledge_src_path(src) if isinstance(src, str) else None
            if fp is None:
                base["has_body"] = False
                base["body"] = None
                return base
            try:
                text = fp.read_text(encoding="utf-8", errors="replace")
            except OSError:
                base["has_body"] = False
                base["error"] = "unreadable"
                return base
            _fm, body = _split_frontmatter(text)
            base["src"] = src.strip()
            base["has_body"] = True
            base["body"] = body.strip()
            return base
        return {"id": nid, "has_body": False, "error": "unknown node"}

    def log_listing(self) -> List[Dict[str, Any]]:
        """py-1.9.0 — Descending-by-date list of `.meshkore/log/*.md`
        narrative day-files. Just metadata (name, date, size, mtime);
        callers fetch the body via `/log/<filename>` for paged display
        in the cockpit Diary tab. Dotfiles + non-.md files are skipped.

        Returned shape:
            [{ "name": "2026-05-27.md", "date": "2026-05-27",
               "size": 12345, "mtime": "2026-05-27T21:00:00Z" }]
        """
        if not self.paths.log_dir.exists():
            return []
        out = []
        for f in self.paths.log_dir.iterdir():
            if not f.is_file() or f.name.startswith("."):
                continue
            if f.suffix.lower() != ".md":
                continue
            # Most filenames are `YYYY-MM-DD.md`. The few that aren't
            # (handoff notes etc.) get `date: null`.
            stem = f.stem
            date = (
                stem
                if (
                    len(stem) == 10
                    and stem[4] == "-"
                    and stem[7] == "-"
                    and stem[:4].isdigit()
                    and stem[5:7].isdigit()
                    and stem[8:10].isdigit()
                )
                else None
            )
            try:
                st = f.stat()
                size = st.st_size
                mtime = datetime.fromtimestamp(st.st_mtime, tz=timezone.utc).strftime(
                    "%Y-%m-%dT%H:%M:%SZ"
                )
            except OSError:
                size = None
                mtime = None
            out.append(
                {
                    "name": f.name,
                    "date": date,
                    "size": size,
                    "mtime": mtime,
                }
            )
        # Dated entries descending (newest → oldest), then any extras
        # (handoff notes etc.) appended in stable filename order.
        dated = sorted(
            [e for e in out if e["date"]], key=lambda e: e["date"], reverse=True
        )
        extras = sorted([e for e in out if not e["date"]], key=lambda e: e["name"])
        return dated + extras


# ── inlined from daemon/walls.py (DM3+ bundle) ─────────────────────────
"""walls.py — initiative wall ordering (WallsMixin).

The cockpit's roadmap UI arranges initiatives into four walls — active / next /
backlog / archived — and persists each one's position within its wall via a
`wall_order: <int>` frontmatter field. This mixin owns:

  GET  /initiative/walls    → { active:[id…], next:[…], backlog:[…], archived:[…] }
  POST /initiative/reorder  → move an initiative to (wall, order), recompact

The status⇄wall mapping: active→active, next→next, done→archived, everything
else (backlog/blocked/unknown)→backlog. `wall_order` is OPTIONAL — initiatives
without it sort LAST in their wall by filename, so every pre-existing initiative
keeps working (back-compat). Coexists with the legacy linked-list `next:`
ordering; the UI reads `wall_order` only.

Daemon facet (mixin): uses self.paths / self.hub / self.state_manager.
"""


from typing import Any, Dict, List, Optional


_WALLS = ("active", "next", "backlog", "archived")
# wall → the status frontmatter value written when an initiative moves there.
_WALL_STATUS = {
    "active": "active",
    "next": "next",
    "backlog": "backlog",
    "archived": "done",
}
_FAR = 10**9  # sort key for initiatives with no wall_order → end of the wall


def _wall_of(fm: Dict[str, Any]) -> str:
    """Which wall an initiative belongs to. The `archived` flag wins — it's an
    explicit operator action that build_state's archive-reconcile never reverts
    (the reconcile only flips `status`/completed_at, e.g. done→active when child
    tasks are still open). Otherwise the wall follows status."""
    if fm.get("archived"):
        return "archived"
    s = normalize_status(fm.get("status"))
    if s == "active":
        return "active"
    if s == "next":
        return "next"
    if s == "done":
        return "archived"
    return "backlog"  # backlog, blocked, unknown


def _wall_order_of(fm: Dict[str, Any]) -> Optional[int]:
    """Read `wall_order` as an int, or None when absent/invalid. `bool` is an
    int subclass — reject it so `wall_order: true` never reads as 1."""
    v = fm.get("wall_order")
    if isinstance(v, bool):
        return None
    if isinstance(v, int):
        return v
    if isinstance(v, str) and v.strip().lstrip("-").isdigit():
        return int(v)
    return None


class WallsMixin:
    def _initiative_fms(self) -> List[tuple]:
        """[(filename_stem, id, frontmatter)] for every initiative .md,
        filename-sorted. Skips files without an `id`."""
        out: List[tuple] = []
        d = self.paths.initiatives
        if not d.exists():
            return out
        for p in sorted(d.glob("*.md")):
            try:
                fm = parse_frontmatter(p.read_text(errors="replace"))
            except OSError:
                continue
            iid = fm.get("id")
            if iid:
                out.append((p.stem, str(iid), fm))
        return out

    def initiative_walls(self) -> Dict[str, List[str]]:
        """The four walls, each a list of initiative ids ordered by wall_order
        asc (missing → last), ties by filename."""
        buckets: Dict[str, List[tuple]] = {w: [] for w in _WALLS}
        for stem, iid, fm in self._initiative_fms():
            buckets[_wall_of(fm)].append((_wall_order_of(fm), stem, iid))
        out: Dict[str, List[str]] = {}
        for w in _WALLS:
            items = sorted(
                buckets[w], key=lambda t: (t[0] if t[0] is not None else _FAR, t[1])
            )
            out[w] = [iid for _, _, iid in items]
        return out

    def initiative_reorder(self, body: Dict[str, Any]):
        iid = str(body.get("id") or "").strip()
        wall = str(body.get("wall") or "").strip()
        order = body.get("order")
        if not iid:
            return 400, {"error": "id required"}
        if wall not in _WALLS:
            return 400, {"error": f"wall must be one of {list(_WALLS)}"}
        if not isinstance(order, int) or isinstance(order, bool):
            return 400, {"error": "order (int) required"}
        path = self.paths.initiatives / f"{iid}.md"
        if not path.exists():
            return 404, {"error": "unknown initiative", "id": iid}
        try:
            fm = parse_frontmatter(path.read_text(errors="replace"))
        except OSError as e:
            return 500, {"error": f"read failed: {e}"}

        # Update status/archived first so the moved initiative is a member of
        # the destination wall BEFORE we recompact it.
        #  • → archived: status:done + archived:true. The `archived` flag is what
        #    holds the wall even if the archive-reconcile reverts status→active
        #    (open child tasks); completed_at is left untouched.
        #  • → any other wall: status:<wall>, and CLEAR a stale `archived` flag
        #    (else _wall_of would keep it in archived).
        if _wall_of(fm) != wall:
            patch: Dict[str, Any] = {"status": _WALL_STATUS[wall]}
            if wall == "archived":
                patch["archived"] = True
            elif fm.get("archived"):
                patch["archived"] = None  # _patch_frontmatter removes None keys
            _patch_frontmatter(path, patch)

        self._recompact_wall(wall, moved_id=iid, target_order=order)
        self.hub.broadcast(
            {"type": "initiative.reordered", "id": iid, "wall": wall, "ts": _iso_now()}
        )
        # Rebuild so /state emits the new wall_order values immediately.
        self.state_manager.rebuild(broadcast=True)
        return 200, {"ok": True, "id": iid, "wall": wall, "order": order}

    def _recompact_wall(self, wall: str, *, moved_id: str, target_order: int) -> None:
        """Renumber every initiative in `wall` to wall_order 0,1,2,… (no gaps),
        with `moved_id` inserted at `target_order`. Writes only the files whose
        wall_order actually changes (_patch_frontmatter is a no-op otherwise)."""
        members = [
            (_wall_order_of(fm), stem, iid)
            for stem, iid, fm in self._initiative_fms()
            if _wall_of(fm) == wall
        ]
        ordered = [
            iid
            for _, _, iid in sorted(
                (m for m in members if m[2] != moved_id),
                key=lambda t: (t[0] if t[0] is not None else _FAR, t[1]),
            )
        ]
        idx = max(0, min(int(target_order), len(ordered)))
        ordered.insert(idx, moved_id)
        for pos, mid in enumerate(ordered):
            _patch_frontmatter(
                self.paths.initiatives / f"{mid}.md", {"wall_order": pos}
            )


# ── inlined from daemon/chatread.py (DM3+ bundle) ─────────────────────────
"""chatread.py — extracted from readapi.py (daemon-architecture-v2 Phase 3).

ChatReadMixin: methods moved VERBATIM out of QueryMixin; Daemon inherits both so
every self.* still resolves on the combined instance -> byte-identical."""


from typing import Any, Dict, List, Optional, Tuple



class ChatReadMixin:
    def chat_convs(self) -> List[Dict[str, Any]]:
        """Canonical list of every conv known to the daemon — union of
        conv_meta.json sidecar entries, live ChatRunner convs, and the
        ChatArchive registry. One source of truth so the cockpit no
        longer has to reconstruct the rail by walking the last 500
        timeline events.

        Per entry:
            conv               — conv id
            agent_type         — normalised role (slug-implied wins)
            agent_id           — A### if assigned
            parent_conv        — for subagents
            initiative_id      — work-* convs and the architect when known
            task_id            — work-* convs
            archived           — bool; archived_at + by when true
            live               — own ChatRunner is streaming RIGHT NOW
            coordinating       — has >=1 live child via parent_conv
            waiting_on         — list of child convs currently live
            created_at         — first-seen ts (from timeline; falls back to
                                  archive entry or "" if neither exists)
            last_activity_at   — most recent timeline event ts for this conv
            msg_count          — count of user/assistant events in timeline

        Note on cost: `_chat_msg_index()` walks all timeline files once
        per call to compute counts + ts boundaries. On small clusters
        (<10k events total) this is sub-millisecond; on big clusters we
        can later memoise on file mtimes, but YAGNI for the cavioca
        scale we're at today.
        """
        all_meta = self._conv_meta_load()
        live = set(self.chat_sessions.list_active())
        archived_list = self.chat_archive.list()  # [{conv, archived_at, by}, …]
        archived_by_conv: Dict[str, Dict[str, Any]] = {
            a["conv"]: a for a in archived_list
        }
        msg_index = self._chat_msg_index()

        # Build the union of all conv ids we know about.
        all_convs: set = set()
        all_convs.update(all_meta.keys())
        all_convs.update(live)
        all_convs.update(archived_by_conv.keys())
        all_convs.update(msg_index.keys())

        # Build parent → children map across the conv_meta entries that
        # name a parent, restricted to live children (the cockpit only
        # cares about "currently waiting on X").
        children_by_parent: Dict[str, List[str]] = {}
        for c in live:
            p = (all_meta.get(c) or {}).get("parent_conv")
            if p:
                children_by_parent.setdefault(str(p), []).append(c)

        entries: List[Dict[str, Any]] = []
        for conv in all_convs:
            meta = all_meta.get(conv) or {}
            arch = archived_by_conv.get(conv)
            idx = msg_index.get(conv) or {}
            is_live = conv in live
            kids = children_by_parent.get(conv) or []
            entry: Dict[str, Any] = {
                "conv": conv,
                "agent_type": _agent_type_normalised(
                    _agent_type_from_conv_slug(conv) or meta.get("agent_type")
                ),
                "agent_id": meta.get("agent_id"),
                "parent_conv": meta.get("parent_conv"),
                "initiative_id": meta.get("initiative_id"),
                "task_id": meta.get("task_id"),
                # MP1 (py-1.13.3) — surface the per-conv model preference
                # so the cockpit can show "running on opus" / etc. in
                # the scope strip alongside the agent role.
                "model": meta.get("model"),
                # MP3 (py-1.13.4) — per-conv effort (reasoning depth).
                "effort": meta.get("effort"),
                "archived": arch is not None,
                "archived_at": arch.get("archived_at") if arch else None,
                "archived_by": arch.get("by") if arch else None,
                "live": is_live,
                "coordinating": (not is_live) and bool(kids),
                "waiting_on": sorted(kids),
                "created_at": idx.get("first_ts")
                or (arch.get("archived_at") if arch else ""),
                "last_activity_at": idx.get("last_ts") or "",
                "msg_count": int(idx.get("count") or 0),
            }
            # CU1 (py-1.13.3) — cumulative token usage + cost for the
            # conv. None when no turn has finalised yet (the cockpit
            # hides the chip). Accumulated in ChatSessions; resets on
            # daemon restart (persisting is `usage-ledger` territory).
            usage = self.chat_sessions.usage_total(conv)
            if usage is not None:
                entry["usage"] = usage
            # SRL2 (py-1.13.1) — for live convs, attach `current_turn`
            # (partial_text + started_at + counters) and `queue` (the
            # in-memory ChatSessions.pending list). Lets a cockpit
            # that just connected rehydrate mid-turn UI without
            # waiting for the first WS delta. Both fields are
            # OPTIONAL — older cockpits ignore them. Cap: single
            # dict lookup + a 16 KB partial_text slice per live
            # conv, so cheap even with many active sessions.
            if is_live:
                snap = self.chat_sessions.turn_snapshot(conv)
                if snap is not None:
                    if snap.get("current_turn"):
                        entry["current_turn"] = snap["current_turn"]
                    if snap.get("queue"):
                        entry["queue"] = snap["queue"]
            entries.append(entry)

        # Order: live first, then idle, then archived. Inside each
        # bucket: newest activity first. Single sort with a composite
        # key — bucket ascending + activity-string-inverted so newest
        # ISO ts (which sort lexicographically) ends up on top.
        def _sort_key(e: Dict[str, Any]) -> Tuple[int, str]:
            bucket = 0 if e["live"] else (2 if e["archived"] else 1)
            # Invert the ISO ts per-char so lexicographic ASC == ts DESC.
            ts = e.get("last_activity_at") or ""
            inverted = "".join(chr(255 - ord(c)) for c in ts) if ts else "\xff"
            return (bucket, inverted)

        entries.sort(key=_sort_key)
        return entries

    def _chat_msg_index(self) -> Dict[str, Dict[str, Any]]:
        """Walk every timeline file once, return per-conv counts +
        first/last ts of chat.user / chat.assistant.final events.

        py-1.16.0 (D-CHAT-IDX-01) — memoised on the set of timeline-file
        (path, mtime, size). Previously EVERY call (incl. per-conv
        `/chat/conv/<id>/meta`, which the cockpit polls) re-read and
        DECOMPRESSED all timeline history — O(all events ever) — and the
        `.gz` files are never deleted, so the cost grew monotonically.
        Now we rebuild only when a timeline file actually changed (an
        append bumps mtime+size); otherwise we return the cached index."""
        out: Dict[str, Dict[str, Any]] = {}
        if not self.paths.timeline_dir.exists():
            return out
        files = list(_iter_timeline_files(self.paths))
        try:
            sig = tuple(
                sorted(
                    (str(f), st.st_mtime_ns, st.st_size)
                    for f in files
                    for st in (f.stat(),)
                )
            )
        except OSError:
            sig = None
        cache = getattr(self, "_chat_idx_cache", None)
        if sig is not None and cache is not None and cache[0] == sig:
            return cache[1]
        chat_types = ("chat.user", "chat.assistant", "chat.assistant.final")
        for f in files:
            for ev in _read_timeline_file(f):
                if ev.get("type") not in chat_types:
                    continue
                conv = ev.get("conv")
                if not conv:
                    continue
                ts = str(ev.get("ts") or "")
                slot = out.setdefault(conv, {"count": 0, "first_ts": "", "last_ts": ""})
                slot["count"] += 1
                if ts:
                    if not slot["first_ts"] or ts < slot["first_ts"]:
                        slot["first_ts"] = ts
                    if ts > slot["last_ts"]:
                        slot["last_ts"] = ts
        if sig is not None:
            self._chat_idx_cache = (sig, out)
        return out

    def chat_conv_meta(self, conv: str) -> Dict[str, Any]:
        """One conv's metadata sidecar, normalised. Used by the cockpit
        for deep-links and resync of individual entries without a full
        /chat/convs refetch."""
        all_meta = self._conv_meta_load()
        m = all_meta.get(conv) or {}
        idx = self._chat_msg_index().get(conv) or {}
        arch = self.chat_archive.is_archived(conv)
        return {
            "conv": conv,
            "agent_type": _agent_type_normalised(
                _agent_type_from_conv_slug(conv) or m.get("agent_type")
            ),
            "agent_id": m.get("agent_id"),
            "parent_conv": m.get("parent_conv"),
            "initiative_id": m.get("initiative_id"),
            "task_id": m.get("task_id"),
            "archived": arch,
            "live": self.chat_sessions.has(conv),
            "created_at": idx.get("first_ts") or "",
            "last_activity_at": idx.get("last_ts") or "",
            "msg_count": int(idx.get("count") or 0),
        }

    def chat_conv_messages(
        self,
        conv: str,
        *,
        before_ts: Optional[str] = None,
        limit: int = 200,
    ) -> Dict[str, Any]:
        """Paginated message read for one conv. Returns events of types
        chat.user / chat.assistant / chat.assistant.final / chat.cancelled
        whose ts < `before_ts` (when provided), newest-first, capped to
        `limit`. The cockpit reverses for display order.

        Pagination contract:
            • First page  → call with before_ts unset → newest `limit`.
            • Older page  → call with before_ts = oldest_ts of prior page.
            • has_more    → true iff a full `limit` came back, OR there
                              is at least one further event in the index.
            • oldest_ts   → the ts of the oldest event in the page
                              (cockpit feeds this back as `before_ts`).

        Cost is the same `_iter_timeline_files` walk as `_chat_msg_index`.
        For now we re-walk per request; the optimisation TODO (per-conv
        index files) is documented but unshipped — small clusters don't
        need it."""
        limit = max(1, min(2000, int(limit or 200)))
        wanted_types = (
            "chat.user",
            "chat.assistant",
            "chat.assistant.final",
            "chat.cancelled",
        )
        # Gather candidates across files in arbitrary order, then sort.
        all_events: List[Dict[str, Any]] = []
        if self.paths.timeline_dir.exists():
            for f in _iter_timeline_files(self.paths):
                for ev in _read_timeline_file(f):
                    if ev.get("conv") != conv:
                        continue
                    if ev.get("type") not in wanted_types:
                        continue
                    all_events.append(ev)
        all_events.sort(key=lambda e: str(e.get("ts") or ""))
        if before_ts:
            all_events = [e for e in all_events if str(e.get("ts") or "") < before_ts]
        # Newest-first cap, then re-reverse so the returned list is in
        # chronological order (the cockpit's reducer expects oldest→newest).
        page = all_events[-limit:]
        oldest_in_page = str(page[0].get("ts") or "") if page else ""
        # `has_more` = there exists at least one event older than the
        # oldest_in_page (we cut some off the front).
        has_more = len(all_events) > len(page)
        return {
            "conv": conv,
            "messages": page,
            "count": len(page),
            "has_more": has_more,
            "oldest_ts": oldest_in_page,
        }

    def chat_snapshot(self) -> Dict[str, Any]:
        """Boot consolidated payload. One round-trip on cockpit start
        instead of the old 3-call chain (/state for timeline replay,
        /chat/archives for archived set, /health for active convs).

        Shape kept narrow on purpose — cockpit consumes specific
        sub-keys; if we need more later, add a key. Never expose
        secrets here."""
        return {
            "convs": self.chat_convs(),
            "paused_agent_types": self._paused_agent_types_view(),
            "quota": self.quota.view(),
            "debug": {
                "enabled": debug_enabled(),
            },
            "version": DAEMON_VERSION,
            "generated_at": _iso_now(),
        }


# ── inlined from daemon/credapi.py (DM3+ bundle) ─────────────────────────
"""credapi.py — extracted from readapi.py (daemon-architecture-v2 Phase 3).

CredMixin: methods moved VERBATIM out of QueryMixin; Daemon inherits both so
every self.* still resolves on the combined instance -> byte-identical."""


import os
import re
from typing import Any, Dict, List, Optional, Tuple


_CREDENTIAL_NAME_RE = re.compile(r"^[A-Za-z0-9][A-Za-z0-9._-]{0,63}$")

# Protected names cannot be written or deleted via the API. portal-token
# is the daemon's own auth secret — letting the cockpit overwrite it
# would lock the cockpit out of the daemon on the very next request.
CREDENTIAL_PROTECTED_NAMES = frozenset({"portal-token"})


def _validate_credential_name(name: str) -> Optional[Tuple[int, Dict[str, Any]]]:
    """Returns None when the name is OK, or a (code, body) error tuple
    ready to ship back to the client. Used by every credential CRUD
    endpoint as the first gate."""
    if not isinstance(name, str) or not name:
        return 400, {"error": "credential name required"}
    if not _CREDENTIAL_NAME_RE.match(name):
        return 400, {
            "error": "invalid credential name; allowed: A-Za-z0-9._- (≤64 chars, must start with alnum)",
        }
    if "/" in name or ".." in name:
        return 400, {"error": "path separators not allowed in credential name"}
    return None


class CredMixin:
    def credentials_listing(self) -> List[Dict[str, Any]]:
        """Names + sizes of every file in .meshkore/credentials/.
        Never the contents — the cockpit only needs to know what
        exists, never what's in them. Same security stance as Node."""
        if not self.paths.credentials.exists():
            return []
        out = []
        for f in sorted(self.paths.credentials.iterdir()):
            if f.name.startswith("."):
                continue
            try:
                size = f.stat().st_size if f.is_file() else None
            except OSError:
                size = None
            out.append(
                {
                    "name": f.name,
                    "size": size,
                    "is_symlink": f.is_symlink(),
                    # py-1.11.3 — protected names are listable but the
                    # cockpit's CRUD blocks edit/delete on them. portal-token
                    # is the canonical example: rewriting it from the cockpit
                    # would lock the cockpit out of its own daemon.
                    "protected": f.name in CREDENTIAL_PROTECTED_NAMES,
                }
            )
        return out

    def credential_read(self, name: str) -> Tuple[int, Dict[str, Any]]:
        """Return the credential value for the operator-facing reveal
        action. The cockpit's CredentialsBlock keeps values masked by
        default and only fetches the raw via this endpoint when the
        operator clicks 'reveal'. Auth-required (handled upstream)."""
        valid = _validate_credential_name(name)
        if valid is not None:
            return valid
        path = self.paths.credentials / name
        if not path.exists() or not path.is_file():
            return 404, {"error": "credential not found", "name": name}
        try:
            value = path.read_text(encoding="utf-8")
        except OSError as e:
            return 500, {"error": f"read failed: {e}"}
        return 200, {
            "name": name,
            "value": value,
            "protected": name in CREDENTIAL_PROTECTED_NAMES,
        }

    def credential_write(self, name: str, value: str) -> Tuple[int, Dict[str, Any]]:
        """Create or overwrite a credential file under .meshkore/credentials/.
        Always chmod 600. Refuses protected names (portal-token) so the
        cockpit can't accidentally lock itself out of the daemon."""
        valid = _validate_credential_name(name)
        if valid is not None:
            return valid
        if name in CREDENTIAL_PROTECTED_NAMES:
            return 403, {
                "error": "protected credential — managed by daemon",
                "name": name,
            }
        if not isinstance(value, str):
            return 400, {"error": "value must be a string"}
        self.paths.credentials.mkdir(parents=True, exist_ok=True)
        path = self.paths.credentials / name
        try:
            path.write_text(value, encoding="utf-8")
            os.chmod(path, 0o600)
        except OSError as e:
            return 500, {"error": f"write failed: {e}"}
        _log(f"credential written: {name} ({len(value)} bytes)")
        return 200, {"name": name, "size": len(value.encode("utf-8"))}

    def credential_delete(self, name: str) -> Tuple[int, Dict[str, Any]]:
        valid = _validate_credential_name(name)
        if valid is not None:
            return valid
        if name in CREDENTIAL_PROTECTED_NAMES:
            return 403, {
                "error": "protected credential — managed by daemon",
                "name": name,
            }
        path = self.paths.credentials / name
        if not path.exists():
            return 404, {"error": "credential not found", "name": name}
        try:
            path.unlink()
        except OSError as e:
            return 500, {"error": f"delete failed: {e}"}
        _log(f"credential deleted: {name}")
        return 200, {"deleted": True, "name": name}


# ── inlined from daemon/runnerutil.py (DM3+ bundle) ─────────────────────────
"""runnerutil.py — per-conv claude session-id + CLI discovery helpers.

Extracted from runner.py (daemon-architecture-v2 Phase 3d). Verbatim move;
imported back where used."""


import os
import uuid
from typing import Optional


_CLAUDE_SESSION_NAMESPACE = uuid.UUID("a4f7c1e8-3b29-4d8e-9c52-7f1e3a8d4b62")


def _session_id_for_conv(conv: str) -> str:
    """Deterministic session UUID per conversation id. Stable across
    daemon restarts so `claude -p --session-id <id>` resumes the same
    conversation context + benefits from Anthropic's prompt cache."""
    return str(uuid.uuid5(_CLAUDE_SESSION_NAMESPACE, conv or "default"))


def _find_claude() -> Optional[str]:
    """Locate the `claude` CLI. Heuristic — try shell PATH, then the
    nvm + Homebrew locations we expect on a typical operator laptop."""
    import shutil

    found = shutil.which("claude")
    if found:
        return found
    import glob

    for pattern in [
        os.path.expanduser("~/.nvm/versions/node/v*/bin/claude"),
        "/opt/homebrew/bin/claude",
        "/usr/local/bin/claude",
    ]:
        hits = sorted(glob.glob(pattern), reverse=True)
        if hits and os.access(hits[0], os.X_OK):
            return hits[0]
    return None


# ── inlined from daemon/runneranchor.py (DM3+ bundle) ─────────────────────────
"""runneranchor.py — extracted from runner.py (daemon-architecture-v2 Phase 3d).

RunnerAnchorMixin: methods moved VERBATIM out of ChatRunner; Daemon inherits both so
every self.* resolves on the combined instance -> byte-identical."""


import json
from typing import List



class RunnerAnchorMixin:
    def _resolve_anchor_head(self, more_text: str) -> str:
        """Buffer the head of the reply until we can decide whether
        it opens with an anchor marker. Returns the text that's safe
        to forward downstream (i.e. the head minus any marker line).

        Called for every delta until `_anchor_head_resolved` is True."""
        self._head_buffer += more_text
        # Wait for at least one full line OR a hard 4 KB cap before
        # deciding — protects against fragmented first deltas.
        if "\n" not in self._head_buffer and len(self._head_buffer) < 4096:
            return ""  # hold the entire buffer for now
        m = self._ANCHOR_RE.match(self._head_buffer.lstrip())
        # Strip leading whitespace; re-anchor the offset.
        lstripped_len = len(self._head_buffer) - len(self._head_buffer.lstrip())
        if m:
            raw_payload = m.group(1)
            try:
                payload = json.loads(raw_payload)
            except json.JSONDecodeError as e:
                if self.daemon is not None:
                    try:
                        self.daemon._handle_anchor_rejected(
                            self.conv, f"malformed JSON: {e}", raw=raw_payload
                        )
                    except Exception:
                        pass
                else:
                    _log(f"anchor: malformed JSON in conv {self.conv}: {e}")
                payload = None
            if payload is not None and self.daemon is not None:
                try:
                    self.daemon._handle_anchor(self.conv, payload, raw=raw_payload)
                except Exception as e:
                    _log(f"anchor: handler raised for conv {self.conv}: {e}")
            elif payload is not None:
                # No daemon ref (standalone) — log and continue.
                _log(f"anchor (no daemon ref): conv={self.conv} payload={payload!r}")
            # Consume up to + including the matched marker line.
            consumed_end = lstripped_len + m.end()
            visible = self._head_buffer[consumed_end:]
        else:
            # No marker → operator-visible from the start. Notify the
            # daemon so it can broadcast `conv.anchor_missing` once.
            if self.daemon is not None:
                try:
                    self.daemon._handle_anchor_missing(self.conv)
                except Exception:
                    pass
            visible = self._head_buffer
        self._head_buffer = ""
        self._anchor_head_resolved = True
        return self._strip_anchor_progress(visible)

    def _strip_anchor_progress(self, text: str) -> str:
        """Detect `⟦anchor-progress⟧ {...}` lines anywhere in `text`,
        notify the daemon, and remove them so they don't reach the
        chat thread."""
        # py-1.14.10 — bracket-agnostic fast-path guard (see _ANCHOR_RE).
        if "anchor-progress" not in text:
            return text
        out_parts: List[str] = []
        last = 0
        for m in self._ANCHOR_PROGRESS_RE.finditer(text):
            out_parts.append(text[last : m.start()])
            raw_payload = m.group(1)
            try:
                payload = json.loads(raw_payload)
            except json.JSONDecodeError:
                payload = None
            if payload is not None and self.daemon is not None:
                try:
                    self.daemon._handle_anchor_progress(
                        self.conv, payload, raw=raw_payload
                    )
                except Exception as e:
                    _log(f"anchor-progress: handler raised: {e}")
            last = m.end()
        out_parts.append(text[last:])
        return "".join(out_parts)

    def _strip_all_anchor_markers(self, text: str) -> str:
        """py-1.13.2 (anchor-strip-final fix, 2026-06-12). Belt-and-
        suspenders strip for the FINAL assistant message. The Claude SDK
        emits a `result` event with the entire reply in one piece; when
        present, daemon prefers `result_text` over `_cumulative_text`
        (the latter was already stripped delta-by-delta in
        `_resolve_anchor_head` + `_strip_anchor_progress`). That bypass
        meant `⟦anchor⟧ {...}` and `⟦anchor-progress⟧ {...}` lines
        leaked into the persisted timeline AND the broadcast chat
        message — operator saw the wire-protocol marker in chat.

        This helper sweeps both marker shapes from the final text. Pure
        text scrubbing — the side-effects (anchor handler, init/task
        file creation, conv_meta persist) already ran during the
        streaming pass. We only need to redact for display."""
        # py-1.14.10 — bracket-agnostic fast-path guard (see _ANCHOR_RE).
        # "anchor" in prose is harmless: the regexes still require a
        # bracket-wrapped marker + JSON body, so a bare word never matches.
        if "anchor" not in text:
            return text
        cleaned = self._ANCHOR_RE.sub("", text, count=1)
        cleaned = self._ANCHOR_PROGRESS_RE.sub("", cleaned)
        return cleaned.lstrip("\n")


# ── inlined from daemon/runnerloop.py (DM3+ bundle) ─────────────────────────
"""runnerloop.py — extracted from runner.py (daemon-architecture-v2 Phase 3d).

RunnerLoopMixin: methods moved VERBATIM out of ChatRunner; Daemon inherits both so
every self.* resolves on the combined instance -> byte-identical."""


import json
import re
import secrets
import time
from typing import List, Tuple



class RunnerLoopMixin:
    def _reader_loop(self) -> None:
        assert self.proc and self.proc.stdout
        # FC-2 (daemon-centralized) — this is a DEDICATED background thread that
        # outlives the POST /chat/dispatch request, so the request threadlocal
        # is already cleared. Re-bind this turn's project on THIS thread so every
        # self.daemon.* callback below (record_usage, _maybe_wake_parent_architect,
        # _persist_task_resolution, _handle_anchor*, _broadcast_conv_activity,
        # chat_archive, _conv_meta_load) resolves to THIS project — not the
        # default. Without this, project B's chat corrupts project A's roadmap/
        # conv_meta/archive. self.paths/self.cluster/self.hub on the runner are
        # already project-correct (captured at spawn); this fixes the daemon
        # callbacks that resolve via the threadlocal.
        if self._project_id and self.daemon is not None:
            self.daemon._set_req_project(self._project_id)
        last_emit_at = 0.0
        result_text = ""
        for raw in self.proc.stdout:
            try:
                line = raw.decode("utf-8", "replace").strip()
            except Exception:
                continue
            if not line:
                continue
            try:
                ev = json.loads(line)
            except json.JSONDecodeError:
                continue
            if not isinstance(ev, dict):
                continue
            ev_type = ev.get("type")
            if ev_type == "stream_event":
                inner = ev.get("event") or {}
                if (
                    inner.get("type") == "content_block_delta"
                    and (inner.get("delta") or {}).get("type") == "text_delta"
                ):
                    delta = (inner.get("delta") or {}).get("text") or ""
                    if delta:
                        self.deltas_seen += 1
                        # LAL2 — Anchor protocol head buffering. Until the
                        # first newline (or 4 KB) the delta is held in
                        # `_head_buffer`; once we can decide whether it
                        # opens with `⟦anchor⟧ {...}` we strip the marker
                        # and forward the rest. After the head is resolved
                        # subsequent deltas just pass through the
                        # `⟦anchor-progress⟧` stripper.
                        if not self._anchor_head_resolved:
                            visible = self._resolve_anchor_head(delta)
                            if not self._anchor_head_resolved:
                                # Still buffering; nothing to broadcast yet.
                                continue
                            self._cumulative_text += visible
                        else:
                            self._cumulative_text += self._strip_anchor_progress(delta)
                        now = time.monotonic()
                        if now - last_emit_at > 0.2:
                            last_emit_at = now
                            self.hub.broadcast(
                                {
                                    "type": "chat.assistant.delta",
                                    "author": self.identity,
                                    "conv": self.conv,
                                    "stream_id": self.stream_id,
                                    "text": self._cumulative_text[:16000],
                                    "ts": _iso_now(),
                                }
                            )
                elif (
                    inner.get("type") == "content_block_start"
                    and (inner.get("content_block") or {}).get("type") == "tool_use"
                ):
                    self.tool_calls_count += 1
                    cb = inner.get("content_block") or {}
                    # py-1.5.0 — Persist tool.use to timeline so the
                    # cockpit can replay full turn detail after a reload
                    # or a daemon restart. Previously broadcast-only,
                    # which made historical turns auditable only via
                    # git log of the files the agent touched.
                    self.hub.broadcast(
                        _append_timeline(
                            self.paths,
                            {
                                "type": "tool.use",
                                "author": self.identity,
                                "conv": self.conv,
                                "stream_id": self.stream_id,
                                "tool": cb.get("name"),
                                "input": cb.get("input"),
                            },
                        )
                    )
                continue
            if ev_type == "user":
                for c in (ev.get("message") or {}).get("content") or []:
                    if isinstance(c, dict) and c.get("type") == "tool_result":
                        # py-1.5.0 — Persist tool.result too (was
                        # broadcast-only). Pair-matched to a tool.use
                        # via stream_id in the cockpit.
                        self.hub.broadcast(
                            _append_timeline(
                                self.paths,
                                {
                                    "type": "tool.result",
                                    "author": self.identity,
                                    "conv": self.conv,
                                    "stream_id": self.stream_id,
                                    "ok": not c.get("is_error"),
                                },
                            )
                        )
                continue
            if ev_type == "result" and isinstance(ev.get("result"), str):
                result_text = ev["result"]
                # CU1 (py-1.13.3) — Capture token usage + cost from the
                # SDK's terminal event. claude-code emits e.g.
                #   {"type":"result","result":"…","usage":{
                #       "input_tokens":N,"output_tokens":N,
                #       "cache_read_input_tokens":N,
                #       "cache_creation_input_tokens":N},
                #    "total_cost_usd":N,"num_turns":N}
                # Daemon previously ignored both fields. Stored on the
                # runner so `_finalize_usage` can broadcast + accumulate
                # after the loop exits.
                usage = ev.get("usage")
                if isinstance(usage, dict):
                    self.last_turn_usage = {
                        "input_tokens": int(usage.get("input_tokens") or 0),
                        "output_tokens": int(usage.get("output_tokens") or 0),
                        "cache_read_input_tokens": int(
                            usage.get("cache_read_input_tokens") or 0
                        ),
                        "cache_creation_input_tokens": int(
                            usage.get("cache_creation_input_tokens") or 0
                        ),
                    }
                cost = ev.get("total_cost_usd")
                if isinstance(cost, (int, float)):
                    self.last_turn_cost_usd = float(cost)
        # Finalize. py-1.13.2 — `result_text` (from the Claude SDK
        # `result` event) was bypassing the anchor stripper because the
        # stripper runs delta-by-delta on `_cumulative_text`. Sweep both
        # marker kinds from the final text before persisting/broadcasting.
        final_text = self._strip_all_anchor_markers(
            result_text or self._cumulative_text
        )
        # py-1.21.1 — TRANSIENT API-ERROR RETRY SHIELD (TR1). claude-code
        # 2.1.145 occasionally fails a long interleaved-thinking + multi-
        # tool turn with `API Error: 400 … thinking/redacted_thinking
        # blocks in the latest assistant message cannot be modified` — a
        # CLI bug reconstructing the multi-block assistant message for the
        # tool-loop continuation (the daemon never touches that array), so
        # a fresh spawn rebuilds a clean array and the same turn succeeds.
        # Siblings: transient 5xx / overloaded / rate-limit. These are
        # TRANSPORT failures, NOT task outcomes. Before this shield the
        # error string got persisted as the turn's chat.assistant.final —
        # poisoning EVERY future briefing via `_section_history` — AND woke
        # the parent architect with a bogus task-failure verdict (field
        # 2026-06-18: `_onboarding_v1` exit=1 at content.12 → false
        # one-retry-then-blocked on the roadmap). Re-spawn the SAME turn up
        # to `_MAX_TRANSIENT_RETRIES`; the error is surfaced normally only
        # after the budget is spent. We branch on `result_text` (the raw
        # SDK `result`) so anchor-stripping can't mask the signature.
        if self._maybe_retry_transient(result_text or self._cumulative_text):
            return
        # py-1.7.0 — Harvest REMEMBER: lines into the role's shared
        # memory. Anything the agent flags ("REMEMBER: credentials live
        # at …") gets appended once, deduplicated. Lines are also
        # stripped from the final response shown in the chat so they
        # don't clutter the UI.
        cleaned_text, harvested = self._harvest_remember_lines(final_text)
        if harvested:
            try:
                self._append_role_memory(harvested)
            except Exception as e:
                _log(f"role memory append failed: {e}")
        self.hub.broadcast(
            _append_timeline(
                self.paths,
                {
                    "type": "chat.assistant.final",
                    "author": self.identity,
                    "conv": self.conv,
                    "stream_id": self.stream_id,
                    "text": cleaned_text,
                },
            )
        )
        # CU1 (py-1.13.3) — Broadcast token usage + cost AFTER the
        # final lands. Cockpit ingests via `chat.usage` and updates
        # `chatStore.state.convs[conv].usage` so the operator sees
        # `12.3k in · 4.5k out · $0.15` in the agent's scope strip.
        if self.last_turn_usage is not None and self.daemon is not None:
            try:
                cumulative = self.daemon.chat_sessions.record_usage(
                    self.conv,
                    self.last_turn_usage,
                    self.last_turn_cost_usd,
                )
                # CTX1 (py-1.28.0) — context-window awareness. Resolve the
                # per-PLATFORM policy from this agent type (claude-code knows
                # its window + self-compacts; an unmodelled runtime gets a null
                # policy — no gauge, no compaction claim). `describe()` turns
                # this turn's prompt tokens into a fill ratio + a should_compact
                # flag the cockpit paints as the context gauge / "will compact"
                # hint. See contextpolicy.py for the headless-turn rationale.
                platform = _agent_manifest(self.agent_type).get(
                    "platform", "claude-code"
                )
                context_block = policy_for(platform).describe(
                    self.last_turn_usage, self.model
                )
                self.hub.broadcast(
                    {
                        "type": "chat.usage",
                        "conv": self.conv,
                        "stream_id": self.stream_id,
                        "turn": {
                            **self.last_turn_usage,
                            "cost_usd": self.last_turn_cost_usd,
                        },
                        "total": cumulative,
                        "model": self.model,
                        "context": context_block,
                        "ts": _iso_now(),
                    }
                )
            except Exception as e:
                _log(f"chat.usage broadcast failed for {self.conv}: {e}")
        # py-1.10.4 — surface the exit code in the daemon log so a
        # silent claude failure (empty stdout, no final, etc.) can
        # be traced back to e.g. "exited 1 with stderr 'context
        # length exceeded'". Without this line, every empty-final
        # looked identical regardless of whether claude crashed,
        # blocked on a tool, or genuinely had nothing to say.
        exit_code = self.proc.wait() if self.proc else None
        text_len = len(cleaned_text or "")
        _log(
            f"claude({self.conv}) exit={exit_code} stream={self.stream_id} "
            f"text_len={text_len} agent_type={self.agent_type}"
        )
        _debug_emit(
            "subagent-final",
            msg=f"{self.conv} exit={exit_code} text_len={text_len}",
            lvl=("warn" if exit_code not in (None, 0) else "info"),
            conv=self.conv,
            agent_id=self.agent_id,
            data={
                "agent_type": self.agent_type,
                "exit": exit_code,
                "text_len": text_len,
                "stream_id": self.stream_id,
                "preview": (cleaned_text or "")[:200],
            },
        )
        self.hub.broadcast(
            {
                "type": "task.finished",
                "id": f"chat:{self.conv}",
                "ts": _iso_now(),
                "exit": exit_code,
                "conv": self.conv,
            }
        )
        # py-1.10.16 — Architect wake hook. If this conv was dispatched
        # by a roadmap-architect (parent_conv recorded in conv_meta),
        # post a `[architect-wake]` turn back to the parent so the
        # pass resumes the moment the subagent finishes. Without this,
        # the architect would have to poll inside its own turn (burns
        # tokens) or rely on the operator to nudge it.
        if self.daemon is not None:
            try:
                self.daemon._maybe_wake_parent_architect(
                    child_conv=self.conv,
                    child_agent_id=self.agent_id,
                    child_final_text=cleaned_text,
                    child_exit=exit_code,
                )
            except Exception as e:
                _log(f"architect wake hook failed for {self.conv}: {e}")
            # Standard v26 — persist the task's resolution record (frontmatter
            # pointers + `## Resolution` body) when this turn finished a task.
            # Fires for EVERY conv, not just architect children, so a task
            # closed by any agent gets a durable summary.
            try:
                self.daemon._persist_task_resolution(
                    conv=self.conv,
                    agent_id=self.agent_id,
                    final_text=cleaned_text,
                    exit_code=exit_code,
                    start_sha=getattr(self, "_turn_start_sha", None),
                )
            except Exception as e:
                _log(f"task-resolution persist failed for {self.conv}: {e}")
            # py-1.11.0 — Broadcast conv.activity for this conv with
            # live=false override. Fires before ChatSessions._wait pops
            # us from `_s`; the override ensures the cockpit sees the
            # right state regardless of the race.
            try:
                self.daemon._broadcast_conv_activity(self.conv, live_override=False)
            except Exception as e:
                _log(f"conv.activity broadcast on final failed for {self.conv}: {e}")
            # py-1.12.9 — Auto-archive any finished SUBAGENT conv.
            # Criterion broadened from "work-* prefix" (py-1.11.2) to
            # "has parent_conv in meta OR matches `work-*` slug". A
            # subagent is anything the architect dispatched — workers
            # (work-*), deploy, db, testing, and ad-hoc customs all
            # carry `parent_conv` in conv_meta. The new rule catches
            # them uniformly.
            #
            # NOT auto-archived (operator-owned, multi-turn):
            #   - Master `_onboarding_v1` (the Coordinator)
            #   - `roadmap-architect-*` (carries the pass summary)
            #   - Any conv WITHOUT parent_conv and not prefixed work-
            #     (= the operator opened it manually, keep it open)
            #
            # Operator field report 2026-06-06: "garantizar que cuando
            # se lanzan agentes que hacen tareas se cierran. Si el
            # usuario quiere abrir tres a mano y dejarlos ahí no hay
            # problema." This matches the rule exactly: dispatched →
            # auto-archive; operator-opened → leave alone.
            should_auto_archive = False
            if not self.daemon.chat_archive.is_archived(self.conv):
                if self.conv.startswith("work-"):
                    should_auto_archive = True
                elif self.conv == "_onboarding_v1":
                    should_auto_archive = False
                elif self.conv.startswith("roadmap-architect-"):
                    should_auto_archive = False
                else:
                    # Look up parent_conv from meta sidecar.
                    try:
                        meta = self.daemon._conv_meta_load().get(self.conv) or {}
                        if meta.get("parent_conv"):
                            should_auto_archive = True
                    except Exception as e:
                        _log(f"auto-archive meta check failed for {self.conv}: {e}")
            if should_auto_archive:
                try:
                    entry = self.daemon.chat_archive.archive(
                        self.conv,
                        by="auto-subagent-finish",
                    )
                    self.hub.broadcast(
                        {
                            "type": "conv.archived",
                            "conv": self.conv,
                            "archived_at": entry.get("archived_at"),
                            "by": entry.get("by"),
                            "ts": entry.get("archived_at"),
                        }
                    )
                except Exception as e:
                    _log(f"auto-archive of {self.conv} failed: {e}")
        self.done.set()

    # TR1 (py-1.21.1) — re-spawn budget for transport-class API errors.
    # 2 retries = 3 attempts total. Past this we surface the error so a
    # genuinely stuck turn can't loop forever.
    _MAX_TRANSIENT_RETRIES = 2
    # Status codes claude-code surfaces as "API Error: <code> …" that a
    # fresh spawn can clear (overload / upstream / gateway). 400/401/403/
    # 404/413 are deliberately EXCLUDED — those are request-shape problems
    # (bad model id, auth, prompt-too-long) a retry won't fix; the one 400
    # we DO retry is matched by signature below, not by code.
    _TRANSIENT_STATUS_RE = re.compile(r"api error:\s*(?:429|5\d\d)\b")

    def _is_transient_api_error(self, text: str) -> bool:
        """True iff `text` is a claude-code API error that a fresh spawn
        can plausibly clear — a TRANSPORT failure, not a task outcome.
        Conservative: only the explicit allowlist below qualifies."""
        if not text:
            return False
        low = text.strip().lower()
        if not low.startswith("api error"):
            return False
        # NEVER retry request-shape failures — a re-spawn rebuilds the same
        # oversized/invalid request and burns the budget for nothing.
        if "too long" in low or "prompt is too" in low:
            return False
        # The specific 400 we DO retry: the thinking/redacted_thinking
        # "cannot be modified" CLI reconstruction bug — a fresh message
        # array makes it disappear.
        if "cannot be modified" in low or "redacted_thinking" in low:
            return True
        # Transient upstream conditions.
        markers = (
            "overloaded",
            "rate limit",
            "rate_limit",
            "internal server error",
            "service unavailable",
            "bad gateway",
            "gateway timeout",
            "timed out",
            "timeout",
        )
        if any(m in low for m in markers):
            return True
        return bool(self._TRANSIENT_STATUS_RE.search(low))

    def _maybe_retry_transient(self, result_text: str) -> bool:
        """If the turn died on a transient API error and we still have
        budget, reap the dead child, reset per-turn streaming state, and
        re-spawn the SAME turn on a fresh `claude -p` process. Returns
        True when a re-spawn was launched (the caller must `return`
        immediately so the failed run does NOT broadcast a final / wake
        the architect / set `done`). Returns False to let the normal
        finalize path run (success, cancel, non-transient error, or
        budget exhausted)."""
        if self.cancelled:
            return False
        if not self._is_transient_api_error(result_text):
            return False
        # Reap the dead child + confirm it actually failed. A clean exit
        # whose text merely *discusses* an API error must not be retried.
        exit_code = None
        try:
            if self.proc is not None:
                exit_code = self.proc.wait(timeout=5)
        except Exception:
            exit_code = None
        if exit_code in (None, 0):
            return False
        attempt = getattr(self, "_transient_attempt", 0)
        if attempt >= self._MAX_TRANSIENT_RETRIES:
            _log(
                f"claude({self.conv}) transient API error — retry budget "
                f"({self._MAX_TRANSIENT_RETRIES}) exhausted; surfacing error"
            )
            return False
        self._transient_attempt = attempt + 1
        preview = (result_text or "").strip()[:200]
        _log(
            f"claude({self.conv}) transient API error "
            f"(attempt {self._transient_attempt}/{self._MAX_TRANSIENT_RETRIES}) "
            f"— re-spawning. err={preview!r}"
        )
        _debug_emit(
            "transient-retry",
            msg=(
                f"{self.conv} transient API error — re-spawn "
                f"{self._transient_attempt}/{self._MAX_TRANSIENT_RETRIES}"
            ),
            lvl="warn",
            conv=self.conv,
            agent_id=self.agent_id,
            data={
                "attempt": self._transient_attempt,
                "agent_type": self.agent_type,
                "preview": preview,
            },
        )
        # Reset per-turn streaming + anchor + usage state so the fresh run
        # starts from a clean slate (a NEW stream_id so the cockpit treats
        # it as a brand-new bubble rather than appending to the dead one).
        self._cumulative_text = ""
        self._head_buffer = ""
        self._anchor_head_resolved = False
        self.deltas_seen = 0
        self.tool_calls_count = 0
        self.last_turn_usage = None
        self.last_turn_cost_usd = None
        self.stream_id = f"s_{int(time.time() * 1000):x}_{secrets.token_hex(2)}"
        # Small backoff — helps 5xx/overloaded settle; harmless for the
        # thinking-block 400 (which is instant-clearable).
        time.sleep(min(2**self._transient_attempt, 8))
        if self.cancelled:
            return False
        # Fresh spawn → new _reader_loop thread; THIS loop returns. The
        # failed turn's error was never persisted, so `_briefing()` rebuilds
        # clean history (the user turn was persisted at dispatch).
        self.spawn()
        return True

    def _harvest_remember_lines(self, text: str) -> Tuple[str, List[str]]:
        """Extract any `REMEMBER: …` lines from `text` and return
        (cleaned text, list of remembered facts). Case-insensitive on
        the marker; one fact per line."""
        if not text:
            return text, []
        kept: List[str] = []
        harvested: List[str] = []
        for line in text.splitlines():
            stripped = line.strip()
            low = stripped.lower()
            # Allow "REMEMBER: ...", "- REMEMBER: ...", "* REMEMBER: ..."
            for prefix in ("remember:", "- remember:", "* remember:"):
                if low.startswith(prefix):
                    fact = stripped[len(prefix) :].strip()
                    # When the prefix had a list bullet, strip the bullet.
                    if prefix.startswith(("-", "*")):
                        fact = fact.lstrip()
                    if fact:
                        harvested.append(fact)
                    break
            else:
                kept.append(line)
                continue
        cleaned = "\n".join(kept).rstrip()
        return cleaned, harvested

    def _append_role_memory(self, facts: List[str]) -> None:
        """Append facts to `.meshkore/agents/_types/<agent-type>/memory.md`,
        deduplicating against what's already in the file. Each entry
        prefixed with its UTC date so memory has provenance."""
        if not facts:
            return
        from datetime import datetime as _dt

        today = _dt.utcnow().strftime("%Y-%m-%d")
        d = self.paths.agents_dir / "_types" / self.agent_type
        d.mkdir(parents=True, exist_ok=True)
        path = d / "memory.md"
        existing = ""
        try:
            existing = path.read_text(errors="replace") if path.exists() else ""
        except OSError:
            existing = ""
        existing_lc = existing.lower()
        new_blocks: List[str] = []
        for fact in facts:
            if fact.lower() in existing_lc:
                continue
            new_blocks.append(f"- {today} · {fact}")
        if not new_blocks:
            return
        header = ""
        if not existing.strip():
            header = (
                f"# `{self.agent_type}` role memory\n\n"
                f"Long-lived facts captured by past instances of this role "
                f"via `REMEMBER: …` lines. Append-only.\n\n"
            )
        addition = (
            ("\n" if existing and not existing.endswith("\n") else "")
            + "\n".join(new_blocks)
            + "\n"
        )
        with path.open("a", encoding="utf-8") as fh:
            if header:
                fh.write(header)
            fh.write(addition)


# ── inlined from daemon/runnerspawn.py (DM3+ bundle) ─────────────────────────
"""runnerspawn.py — extracted from runner.py (daemon-architecture-v2 Phase 3d).

RunnerSpawnMixin: methods moved VERBATIM out of ChatRunner; Daemon inherits both so
every self.* resolves on the combined instance -> byte-identical."""


import os
import threading
import time



class RunnerSpawnMixin:
    def spawn(self) -> None:
        import subprocess

        claude_bin = _find_claude()
        if not claude_bin:
            err = "claude CLI not found — install via `npm i -g @anthropic-ai/claude-code`"
            _log(err)
            self.hub.broadcast(
                _append_timeline(
                    self.paths,
                    {
                        "type": "chat.assistant.final",
                        "author": self.identity,
                        "conv": self.conv,
                        "stream_id": self.stream_id,
                        "text": f"[runner error] {err}",
                    },
                )
            )
            self.done.set()
            return
        # py-1.6.1 HOTFIX — --session-id from py-1.6.0 caused empty
        # assistant responses in production (claude-code exited
        # silently on subsequent turns of the same conv). Reverted to
        # opt-in via env var MESHKORE_CLAUDE_SESSION_ID=1. Default off
        # until the failure mode is understood and re-tested.
        # The uuid5 helper is preserved so reintroduction is a one-line
        # flip once safe.
        session_id = _session_id_for_conv(self.conv)
        use_session = os.environ.get("MESHKORE_CLAUDE_SESSION_ID", "").strip() in (
            "1",
            "true",
            "yes",
            "on",
        )
        args = [
            claude_bin,
            "-p",
            "--output-format",
            "stream-json",
            "--verbose",
            "--include-partial-messages",
            "--permission-mode",
            "bypassPermissions",
            # Headless: cockpit has no UI to surface interactive question
            # tools. Disallow them so the model defaults to plain-text
            # asks in the chat bubble instead of stalling on a hanging
            # AskUserQuestion / ExitPlanMode call.
            "--disallowed-tools",
            "AskUserQuestion,ExitPlanMode",
        ]
        # MP1 (py-1.13.3) — Per-conv model override. `--model` accepts
        # one of `opus` / `sonnet` / `haiku` or an explicit model id
        # (claude-opus-4-7, etc.). When unset (`auto` / None), we omit
        # the flag entirely and let claude-code pick its default.
        if self.model:
            args.extend(["--model", self.model])
        # MP3 (py-1.13.4) — reasoning-depth dial. Omitted when None
        # ('default' sentinel) so claude-code uses its own default.
        if self.effort:
            args.extend(["--effort", self.effort])
        if use_session:
            args[2:2] = ["--session-id", session_id]
        # py-1.10.5 — Pipe the briefing through stdin instead of
        # appending it as a positional argument. claude 2.1.145
        # rejects a trailing positional that arrives AFTER a
        # multi-value flag (`--disallowed-tools <comma,list>`) — the
        # parser consumes our prompt as another disallowed-tool name
        # or just drops it, and claude exits 1 with stderr:
        #   "Error: Input must be provided either through stdin or
        #    as a prompt argument when using --print"
        # Captured 2026-05-29 by py-1.10.4's stderr drainer (which
        # had been silently dropping this error for every spawn
        # since the cockpit's roadmap-architect feature shipped).
        # Stdin works regardless of argv order, so it's the
        # forward-compatible answer.
        briefing = self._briefing()
        env = {
            **os.environ,
            "MESHKORE_IDENTITY": self.identity,
            "MESHKORE_CONV": self.conv,
            "MESHKORE_SESSION_ID": session_id,
        }
        # Stamped so ChatSessionReaper can apply the hard-timeout check
        # (any runner whose runtime exceeds the reaper's threshold gets
        # force-cancelled). Set BEFORE Popen so even a subprocess that
        # hangs in the OS spawn path gets the timestamp.
        self._started_at = time.time()
        # QX5 — record HEAD at turn start so the resolution can diff
        # exactly what this turn changed (files + commits). Quiet on any
        # failure; resolution just records nothing then.
        try:
            _head = subprocess.run(
                ["git", "rev-parse", "HEAD"],
                cwd=str(self.paths.root),
                capture_output=True,
                text=True,
                timeout=5,
            )
            self._turn_start_sha = (
                _head.stdout.strip() if _head.returncode == 0 else None
            )
        except Exception:  # best-effort telemetry — never break the spawn
            self._turn_start_sha = None
        self.proc = subprocess.Popen(
            args,
            cwd=str(self.paths.root),
            env=env,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            start_new_session=True,
        )
        self.pid = self.proc.pid
        # Write the briefing to stdin and close. claude reads it
        # all (EOF on close) then begins streaming results to stdout.
        try:
            if self.proc.stdin is not None:
                self.proc.stdin.write(briefing.encode("utf-8"))
                self.proc.stdin.close()
        except (BrokenPipeError, OSError) as e:
            _log(f"claude({self.conv}) stdin write failed: {e}")
        _log(
            f"claude({self.conv}) spawned pid={self.pid} agent_type={self.agent_type} "
            f"stream={self.stream_id} briefing_len={len(briefing)}"
        )
        self.hub.broadcast(
            {
                "type": "task.started",
                "id": f"chat:{self.conv}",
                "agent": self.identity,
                "ts": _iso_now(),
                "runner": "claude-code",
                "conv": self.conv,
                "stream_id": self.stream_id,
            }
        )
        # Empty assistant bubble so the cockpit shows progress immediately.
        self.hub.broadcast(
            {
                "type": "chat.assistant.delta",
                "author": self.identity,
                "conv": self.conv,
                "stream_id": self.stream_id,
                "text": "",
                "ts": _iso_now(),
            }
        )
        threading.Thread(target=self._reader_loop, daemon=True).start()
        # py-1.10.4 — stderr drainer. Until this lands, stderr=PIPE
        # was capturing claude's error output but NOBODY READ IT, so
        # every subprocess crash (prompt too long, blocked tool, env
        # issue, segfault) surfaced as "empty chat.assistant.final"
        # with no diagnostic anywhere in the daemon log. The reader
        # loop above only iterates stdout; PIPE'd stderr fills its
        # OS buffer (typically 64 KB) and on overflow Linux/Darwin
        # block claude on its next write — turning a soft failure
        # into an unkillable zombie. Drain it into the daemon log.
        threading.Thread(target=self._stderr_drain, daemon=True).start()

    def _stderr_drain(self) -> None:
        """Read self.proc.stderr line-by-line and forward to the
        daemon log. Tagged with conv so multiple in-flight runners
        don't blur together. Cheap — claude rarely emits much on
        stderr unless it's failing."""
        if not self.proc or not self.proc.stderr:
            return
        for raw in self.proc.stderr:
            try:
                line = raw.decode("utf-8", "replace").rstrip()
            except Exception:
                continue
            if line:
                _log(f"claude({self.conv}) stderr: {line}")


