# The DRAFT the operator gets back always carries the strongest ALIAS
# ("opus") in its `model` field — this is only the wire model for the
# single normalisation request.
_DRAFT_API_MODEL = "claude-opus-4-8"
_ANTHROPIC_URL = "https://api.anthropic.com/v1/messages"
_ANTHROPIC_VERSION = "2023-06-01"


class TeamMixin:
    # ── ATM9: /team HTTP CRUD ──────────────────────────────────────────
    def _team_broadcast(self, event: str, mid: str) -> None:
        """Emit team.created|updated|deleted {id, ts} on the chat.* bus."""
        try:
            if getattr(self, "hub", None) is not None:
                self.hub.broadcast({"type": event, "id": mid, "ts": _iso_now()})
        except Exception as e:  # noqa: BLE001 — a broadcast failure is non-fatal
            _log(f"team broadcast {event} failed: {e}")

    def _team_instance_counts(self) -> Dict[str, int]:
        """Per-member count of LIVE instances = non-archived convs whose
        conv_meta.member == <id>. Joins the conv_meta sidecar (ATM10) with
        the archive store, exactly like /team's `instances` field."""
        counts: Dict[str, int] = {}
        try:
            meta = self._conv_meta_load()
        except Exception:
            return counts
        for conv, entry in (meta or {}).items():
            if not isinstance(entry, dict):
                continue
            member = str(entry.get("member") or "").strip()
            if not member:
                continue
            try:
                if self.chat_archive.is_archived(conv):
                    continue
            except Exception:
                pass
            counts[member] = counts.get(member, 0) + 1
        return counts

    def team_list_http(self) -> Tuple[int, Dict[str, Any]]:
        members = self.team_store.team_list()
        counts = self._team_instance_counts()
        for m in members:
            m["instances"] = counts.get(str(m.get("id") or ""), 0)
        return 200, {"members": members, "count": len(members)}

    def team_get_http(self, mid: str) -> Tuple[int, Dict[str, Any]]:
        try:
            member = self.team_store.team_get(mid)
        except TeamError as e:
            return self._team_err(e)
        counts = self._team_instance_counts()
        member["instances"] = counts.get(mid, 0)
        return 200, member

    def team_create_http(self, body: Dict[str, Any]) -> Tuple[int, Dict[str, Any]]:
        if not isinstance(body, dict):
            return 400, {"error": "JSON object body required"}
        try:
            member = self.team_store.team_create(body, today=_iso_now()[:10])
        except TeamError as e:
            return self._team_err(e)
        mid = str(member["frontmatter"].get("id"))
        self._team_broadcast("team.created", mid)
        return 201, member

    def team_update_http(
        self, mid: str, patch: Dict[str, Any]
    ) -> Tuple[int, Dict[str, Any]]:
        if not isinstance(patch, dict):
            return 400, {"error": "JSON object body required"}
        try:
            member = self.team_store.team_update(mid, patch, today=_iso_now()[:10])
        except TeamError as e:
            return self._team_err(e)
        self._team_broadcast("team.updated", mid)
        return 200, member

    def team_delete_http(self, mid: str) -> Tuple[int, Dict[str, Any]]:
        try:
            self.team_store.team_delete(mid)
        except TeamError as e:
            return self._team_err(e)
        self._team_broadcast("team.deleted", mid)
        return 200, {"ok": True, "deleted": mid}

    @staticmethod
    def _team_err(e: TeamError) -> Tuple[int, Dict[str, Any]]:
        body: Dict[str, Any] = {"error": e.message}
        if getattr(e, "extra", None):
            body.update(e.extra)
        return int(getattr(e, "code", 400)), body

    # ── ATM10: member → dispatch resolution ────────────────────────────
    def _member_dispatch_prep(
        self,
        conv: str,
        member: str,
        *,
        body_agent_type: Optional[str],
        body_model: Optional[str],
        body_effort: Optional[str],
    ) -> Tuple[
        Optional[Tuple[int, Dict[str, Any]]],
        Optional[str],
        Optional[str],
        Optional[str],
    ]:
        """Resolve a `member` binding for a /chat/dispatch turn.

        Returns (err | None, agent_type, model, effort). On any rule
        violation the first element is a ready (code, body) HTTP error and
        the rest are None:
          - unknown member                → 400
          - rebind after ≥1 message       → 409
          - 2nd live singleton instance   → 409 singleton_instance_exists

        Resolution (when OK): agent_type ← member.agent_type; model/effort ←
        member values UNLESS the dispatch body explicitly overrides them
        (overrides win on ANY turn). The caller passes the resolved values
        through to _spawn_chat_turn / conv_meta so they persist.
        """
        try:
            m = self.team_store.team_get(member)
        except TeamError:
            return (
                (400, {"error": f"unknown team member {member!r}", "member": member}),
                None,
                None,
                None,
            )
        fm = m.get("frontmatter") or {}

        # Freeze: a conv already bound to a DIFFERENT member that has spoken
        # (≥1 message) cannot be rebound.
        existing = self._conv_meta_get_member(conv)
        if existing and existing != member and self._conv_has_message(conv):
            return (
                (
                    409,
                    {
                        "error": "member binding is frozen after the first message",
                        "conv": conv,
                        "bound_member": existing,
                        "requested_member": member,
                    },
                ),
                None,
                None,
                None,
            )

        # Singleton: only one live (non-archived) instance across convs.
        if str(fm.get("kind")) == "singleton":
            other = self._singleton_live_conv(member, exclude_conv=conv)
            if other is not None:
                return (
                    (
                        409,
                        {
                            "error": "singleton_instance_exists",
                            "member": member,
                            "conv": other,
                        },
                    ),
                    None,
                    None,
                    None,
                )

        resolved_type = str(fm.get("agent_type") or "custom").strip() or "custom"
        # body overrides win on any turn; member fills the gaps.
        resolved_model = (
            body_model if body_model else (str(fm.get("model") or "").strip() or None)
        )
        resolved_effort = (
            body_effort
            if body_effort
            else (str(fm.get("effort") or "").strip().lower() or None)
        )
        # 'default' effort is a no-op sentinel — treat as no override.
        if resolved_effort in ("default", ""):
            resolved_effort = None
        # body agent_type does NOT override the member's baseline (ATM10:
        # "agent_type ← member's agent_type"). Ignore body_agent_type here.
        _ = body_agent_type
        return None, resolved_type, resolved_model, resolved_effort

    def _conv_has_message(self, conv: str) -> bool:
        """True iff this conv already has ≥1 assistant/user turn on disk —
        used to freeze the member binding after the first message."""
        try:

            for f in _iter_timeline_files(self.paths):
                for ev in _read_timeline_file(f):
                    if ev.get("conv") != conv:
                        continue
                    if ev.get("type") in (
                        "chat.user",
                        "chat.assistant.final",
                        "chat.assistant.delta",
                    ):
                        return True
        except Exception:
            return False
        return False

    def _singleton_live_conv(self, member: str, *, exclude_conv: str) -> Optional[str]:
        """Return the conv id of an existing LIVE (non-archived) instance of
        `member`, or None. Used to enforce kind:singleton."""
        try:
            meta = self._conv_meta_load()
        except Exception:
            return None
        for conv, entry in (meta or {}).items():
            if conv == exclude_conv or not isinstance(entry, dict):
                continue
            if str(entry.get("member") or "").strip() != member:
                continue
            try:
                if self.chat_archive.is_archived(conv):
                    continue
            except Exception:
                pass
            return conv
        return None

    def _team_backfill_onboarding(self) -> None:
        """Bind the coordinator conv (_onboarding_v1) to architect-master on
        boot if it has no member yet (ATM10 'master conv & first boot')."""
        try:
            conv = "_onboarding_v1"
            # Only backfill an EXISTING coordinator conv — never mint one. On a
            # fresh cluster the conv doesn't exist yet; creating a conv_meta
            # entry here would surface a phantom live conv in /chat/snapshot.
            meta = self._conv_meta_load()
            entry = meta.get(conv)
            if not isinstance(entry, dict):
                return
            if str(entry.get("member") or "").strip():
                return
            if not self.team_store.exists("architect-master"):
                return
            agent_type, agent_id = self._conv_meta_get(conv)
            self._conv_meta_set(conv, agent_type, agent_id, member="architect-master")
            _log("team: backfilled _onboarding_v1 → member=architect-master")
        except Exception as e:  # noqa: BLE001 — backfill is best-effort
            _log(f"team onboarding backfill skipped: {e}")

    # ── ATM5: /team/draft — free text → structured member draft ────────
    def team_draft(self, body: Dict[str, Any]) -> Tuple[int, Dict[str, Any]]:
        if not isinstance(body, dict):
            return 400, {"error": "JSON object body required"}
        raw_text = str(body.get("raw_text") or body.get("text") or "").strip()
        if not raw_text:
            return 400, {"error": "raw_text required"}
        name = str(body.get("name") or "").strip()
        emoji = str(body.get("emoji") or "").strip()

        key = self._anthropic_key()
        if not key:
            return 503, {
                "error": "llm_unavailable",
                "hint": (
                    "no Anthropic API key found in .meshkore/credentials/ "
                    "(anthropic.key / anthropic.env / ANTHROPIC_API_KEY / "
                    "claude-code.env) — set one, or fill the member fields by hand."
                ),
            }

        # Slug: snake-lowercase of name, dedup against existing ids. If the
        # base slug already exists, 409 with a free suggestion (ATM5).
        base = self._slugify(name or raw_text[:24])
        if not base:
            base = "member"
        if self.team_store.exists(base):
            return 409, {
                "error": "slug_exists",
                "id": base,
                "suggested": self._free_slug(base),
            }

        try:
            draft = self._llm_member_draft(raw_text, name=name, emoji=emoji, key=key)
        except _LlmError as e:
            return 503, {"error": "llm_unavailable", "hint": str(e)}

        draft["id"] = base
        if name:
            draft["name"] = name
        if emoji:
            draft["emoji"] = emoji
        draft.setdefault("name", name or base)
        draft.setdefault("emoji", "🤖")
        # Policy: strongest alias, tune with effort; drafts are always profiles.
        draft["model"] = STRONGEST_MODEL_ALIAS
        draft["effort"] = "default"
        draft["kind"] = "profile"
        draft["required"] = False
        return 200, draft

    def _anthropic_key(self) -> Optional[str]:
        """Resolve an Anthropic API key from env or .meshkore/credentials/.
        Never logs the value. Returns None when absent."""
        env = (os.environ.get("ANTHROPIC_API_KEY") or "").strip()
        if env:
            return env
        creds = self.paths.credentials
        candidates = (
            "anthropic.key",
            "anthropic-api.key",
            "anthropic.env",
            "claude-code.env",
        )
        for name in candidates:
            p = creds / name
            try:
                if not p.is_file():
                    continue
                text = p.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            k = self._extract_key(text)
            if k:
                return k
        return None

    @staticmethod
    def _extract_key(text: str) -> Optional[str]:
        # `.key` files may be the bare token; `.env` files are KEY=VALUE lines.
        for line in text.splitlines():
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            if "=" in line:
                _, _, val = line.partition("=")
                val = val.strip().strip('"').strip("'")
            else:
                val = line
            if val.startswith("sk-ant"):
                return val
        stripped = text.strip()
        if stripped.startswith("sk-ant"):
            return stripped
        return None

    def _slugify(self, s: str) -> str:
        s = (s or "").strip().lower()
        s = re.sub(r"[^a-z0-9]+", "-", s).strip("-")
        s = s[:32].strip("-")
        if s and not re.match(r"^[a-z]", s):
            s = "m-" + s
            s = s[:32].strip("-")
        return s if _ID_RE.match(s or "") else (s or "")

    def _free_slug(self, base: str) -> str:
        for n in range(2, 100):
            cand = f"{base[:30]}-{n}"
            if not self.team_store.exists(cand):
                return cand
        return f"{base[:28]}-{_iso_now()[-6:-1]}"

    def _llm_member_draft(
        self, raw_text: str, *, name: str, emoji: str, key: str
    ) -> Dict[str, Any]:
        """Single short Messages-API call → parsed member draft dict.
        Raises _LlmError on any transport/parse failure."""
        system = (
            "You normalise an operator's free-text description of an AI team "
            "member into a structured JSON draft. Reply with ONE json object and "
            "NOTHING else. Keys: name (string), emoji (one glyph), refs (array of "
            "path-like strings you find VERBATIM in the text — .meshkore/..., "
            "apps/..., webapp/..., file paths/urls; never invent), "
            "credentials_hint (string; '(none — read-only role)' if the text says "
            "no credentials), prompt (a markdown system prompt for the member: "
            "mission, responsibilities, attributions & limits, reference docs — "
            "match the language the operator wrote in). Do NOT include id, model, "
            "effort or kind — those are set by policy."
        )
        user = raw_text
        if name:
            user = f"name: {name}\n{user}"
        if emoji:
            user = f"emoji: {emoji}\n{user}"
        payload = json.dumps(
            {
                "model": _DRAFT_API_MODEL,
                "max_tokens": 1500,
                "system": system,
                "messages": [{"role": "user", "content": user}],
            }
        ).encode("utf-8")
        req = urllib.request.Request(
            _ANTHROPIC_URL,
            data=payload,
            method="POST",
            headers={
                "content-type": "application/json",
                "x-api-key": key,
                "anthropic-version": _ANTHROPIC_VERSION,
            },
        )
        try:
            with urllib.request.urlopen(req, timeout=60) as resp:
                raw = resp.read().decode("utf-8")
        except urllib.error.HTTPError as e:
            detail = ""
            try:
                detail = e.read().decode("utf-8")[:300]
            except Exception:
                pass
            raise _LlmError(f"Anthropic API {e.code}: {detail}") from e
        except (urllib.error.URLError, OSError) as e:
            raise _LlmError(f"Anthropic API unreachable: {e}") from e
        try:
            data = json.loads(raw)
            parts = data.get("content") or []
            text = "".join(
                p.get("text", "") for p in parts if isinstance(p, dict)
            ).strip()
        except Exception as e:
            raise _LlmError(f"unexpected API response: {e}") from e
        draft = self._parse_json_object(text)
        if not isinstance(draft, dict):
            raise _LlmError("model did not return a JSON object")
        # Keep only known keys; coerce refs to a list of strings.
        out: Dict[str, Any] = {}
        if draft.get("name"):
            out["name"] = str(draft["name"]).strip()
        if draft.get("emoji"):
            out["emoji"] = str(draft["emoji"]).strip()
        refs = draft.get("refs")
        out["refs"] = (
            [str(r).strip() for r in refs if str(r).strip()]
            if isinstance(refs, list)
            else []
        )
        if draft.get("credentials_hint"):
            out["credentials_hint"] = str(draft["credentials_hint"]).strip()
        out["prompt"] = str(draft.get("prompt") or "").strip()
        return out

    @staticmethod
    def _parse_json_object(text: str) -> Any:
        text = text.strip()
        # Strip ```json fences if the model wrapped its reply.
        if text.startswith("```"):
            text = re.sub(r"^```[a-zA-Z]*\n", "", text)
            text = re.sub(r"\n```$", "", text).strip()
        try:
            return json.loads(text)
        except json.JSONDecodeError:
            # Salvage the first {...} block.
            start = text.find("{")
            end = text.rfind("}")
            if 0 <= start < end:
                try:
                    return json.loads(text[start : end + 1])
                except json.JSONDecodeError:
                    return None
        return None


class _LlmError(Exception):
    """Internal — any failure talking to the draft LLM. Surfaced as 503."""


# ── inlined from daemon/quota.py (DM3+ bundle) ─────────────────────────
"""Per-(platform, model) quota state + background prober.

Auto-pause logic for rate-limited LLM keys. The daemon classifies a
subagent's final output as ``success`` / ``rate-limited`` / other; on
``rate-limited`` it pauses the corresponding quota key. ``QuotaProber``
wakes every ``TICK_SECS`` and re-probes paused keys with a minimal
claude turn; on ``success`` it clears the pause.

Both classes are constructor-injected the daemon ref so they can call
``self.daemon._spawn_chat_turn(...)``, ``self.daemon._classify_subagent_final(...)``,
``self.daemon._broadcast_conv_activity(...)``. Coupling is intentional —
the prober's whole job is to talk to subagents the daemon manages.

Bundler note: shared helpers (``_log``, ``_iso_now``, ``_iso_at``,
``_debug_emit``) come from utils; ``_agent_manifest`` + ``AGENT_PROMPTS``
come from prompts (DM-modularize-2 — was a local shadow stub, now a real
import, so the bundle no longer relies on definition order). Source-tree
dev runs ``QuotaState`` correctly; ``QuotaProber.probe_one`` requires the
full daemon and is exercised only in production / integration runs."""



import json
import threading
import time
from datetime import datetime
from pathlib import Path
from typing import Any, Dict, List, Optional




class QuotaState:
    """Append-only ledger of (platform, model) → pause-state.

    File format (`.meshkore/.runtime/quota-state.json`):

        {
          "version": 1,
          "updated_at": "...",
          "by_key": {
            "claude-code/auto": {
              "platform": "claude-code",
              "model": "auto",
              "paused": true,
              "paused_at": "...",
              "paused_until": "...",
              "paused_until_epoch": 1780202625,
              "reason": "Claude AI usage limit reached (work-…)",
              "first_rate_limit_at": "...",
              "consecutive_rate_limits": 2,
              "probes": [
                {"at": "...", "conv": "probe-…", "outcome": "rate-limited"}
              ],
              "last_success_at": "...",
              "last_success_conv": "work-…"
            }
          }
        }

    All writes go through `_persist_locked` (tmp + atomic rename).
    All reads return defensive copies — callers must NOT mutate the
    returned dicts directly.
    """

    # Conservative default: claude-code Pro/Max rolling window is 5h
    # but the practical sliding window resets in chunks. 60 min is the
    # smallest useful probe interval that still lets a long block clear
    # in under an hour. Operator can extend via the pause endpoint.
    DEFAULT_PAUSE_SECS = 60 * 60
    MAX_PROBE_HISTORY = 20

    def __init__(self, path: "Path") -> None:
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._lock = threading.Lock()
        self._data = self._load()

    def _load(self) -> Dict[str, Any]:
        try:
            if self.path.exists():
                raw = json.loads(self.path.read_text() or "{}")
                if isinstance(raw, dict) and "by_key" in raw:
                    return raw
        except Exception as e:
            _log(f"quota-state: load failed ({e}) — starting empty")
        return {"version": 1, "by_key": {}, "updated_at": _iso_now()}

    def _persist_locked(self) -> None:
        self._data["updated_at"] = _iso_now()
        try:
            atomic_write_json(self.path, self._data, sort_keys=True)
        except OSError as e:
            _log(f"quota-state: persist failed ({e})")

    def _entry(self, key: str) -> Dict[str, Any]:
        return self._data.setdefault("by_key", {}).setdefault(
            key,
            {
                "platform": key.split("/", 1)[0] if "/" in key else key,
                "model": key.split("/", 1)[1] if "/" in key else "auto",
                "paused": False,
                "probes": [],
                "consecutive_rate_limits": 0,
            },
        )

    def is_paused(self, key: str) -> bool:
        """True iff `key` has an unexpired pause. Reaps stale entries."""
        with self._lock:
            e = self._data.get("by_key", {}).get(key)
            if not e or not e.get("paused"):
                return False
            until = int(e.get("paused_until_epoch") or 0)
            if until <= int(time.time()):
                e["paused"] = False
                self._persist_locked()
                return False
            return True

    def get(self, key: str) -> Optional[Dict[str, Any]]:
        with self._lock:
            e = self._data.get("by_key", {}).get(key)
            return dict(e) if e else None

    def pause(
        self,
        key: str,
        *,
        reason: str,
        duration_secs: Optional[int] = None,
        platform: Optional[str] = None,
        model: Optional[str] = None,
    ) -> Dict[str, Any]:
        secs = max(60, int(duration_secs or self.DEFAULT_PAUSE_SECS))
        now = int(time.time())
        until = now + secs
        with self._lock:
            e = self._entry(key)
            if platform:
                e["platform"] = platform
            if model:
                e["model"] = model
            # Track consecutive lockouts so the prober can escalate
            # the cooldown if the same key keeps coming back locked.
            if e.get("paused") and (e.get("paused_until_epoch") or 0) > now:
                e["consecutive_rate_limits"] = (
                    int(e.get("consecutive_rate_limits") or 0) + 1
                )
            else:
                # First lockout in this streak — note the start time.
                e["consecutive_rate_limits"] = (
                    int(e.get("consecutive_rate_limits") or 0) + 1
                )
                e["first_rate_limit_at"] = _iso_now()
            e["paused"] = True
            e["paused_at"] = _iso_now()
            e["paused_until"] = _iso_at(until)
            e["paused_until_epoch"] = until
            e["reason"] = (reason or "")[:240]
            self._persist_locked()
            return dict(e)

    def unpause(self, key: str) -> bool:
        with self._lock:
            e = self._data.get("by_key", {}).get(key)
            if not e or not e.get("paused"):
                return False
            e["paused"] = False
            e["consecutive_rate_limits"] = 0
            self._persist_locked()
            return True

    def record_probe(
        self,
        key: str,
        conv: str,
        outcome: str,
    ) -> None:
        """Append a probe outcome to the per-key history. Trims to
        MAX_PROBE_HISTORY so the file doesn't grow unbounded."""
        with self._lock:
            e = self._entry(key)
            probes = e.setdefault("probes", [])
            probes.append({"at": _iso_now(), "conv": conv, "outcome": outcome})
            if len(probes) > self.MAX_PROBE_HISTORY:
                del probes[: len(probes) - self.MAX_PROBE_HISTORY]
            if outcome == "success":
                e["last_success_at"] = _iso_now()
                e["last_success_conv"] = conv
                e["paused"] = False
                e["consecutive_rate_limits"] = 0
            self._persist_locked()

    def record_success(self, key: str, conv: str) -> None:
        """Mark a non-probe success — resets the consecutive-fail
        counter so a transient rate-limit doesn't escalate forever."""
        with self._lock:
            e = self._entry(key)
            e["last_success_at"] = _iso_now()
            e["last_success_conv"] = conv
            e["consecutive_rate_limits"] = 0
            self._persist_locked()

    def keys_due_for_probe(self, *, max_age_secs: int = 60) -> List[str]:
        """Paused keys whose `paused_until` elapsed at least
        `max_age_secs` seconds ago AND haven't been probed in the
        last 60s. Used by QuotaProber to pick what to probe."""
        out: List[str] = []
        now = int(time.time())
        with self._lock:
            for key, e in (self._data.get("by_key") or {}).items():
                if not e.get("paused"):
                    continue
                until = int(e.get("paused_until_epoch") or 0)
                if now - until < max_age_secs:
                    continue
                # Throttle probe rate per key — never more than 1/min.
                last_probe = (e.get("probes") or [])[-1:]
                if last_probe:
                    try:
                        probe_ts = datetime.fromisoformat(
                            str(last_probe[0].get("at") or "").replace("Z", "+00:00")
                        ).timestamp()
                        if now - probe_ts < 60:
                            continue
                    except (ValueError, TypeError):
                        pass
                out.append(key)
        return out

    def view(self) -> Dict[str, Dict[str, Any]]:
        """Snapshot of all entries, with stale 'paused' flags reaped.
        Read-only for /health + /quota consumers."""
        now = int(time.time())
        out: Dict[str, Dict[str, Any]] = {}
        with self._lock:
            for key, e in (self._data.get("by_key") or {}).items():
                e2 = dict(e)
                if e2.get("paused") and int(e2.get("paused_until_epoch") or 0) <= now:
                    e2["paused"] = False
                out[key] = e2
        return out

    def paused_view(self) -> Dict[str, Dict[str, Any]]:
        """Subset of view() including only currently-paused keys."""
        return {k: v for k, v in self.view().items() if v.get("paused")}


# ── inlined from daemon/quotaprober.py (DM3+ bundle) ─────────────────────────
"""quotaprober.py — QuotaProber — wakes paused quota keys.

Extracted from quota.py (daemon-architecture-v2 Phase 3d). Verbatim move;
imported back where used."""


import threading
import time
from typing import Any, Optional



class QuotaProber:
    """py-1.10.27 — Background thread that probes paused quota keys.

    Every TICK_SECS, scans `QuotaState.keys_due_for_probe()` and
    dispatches a minimal Claude Code subprocess against each. Reads
    the final, classifies, and either un-pauses the key (probe
    succeeded → quota is back) or extends the pause by another
    DEFAULT cooldown (probe still rate-limited → still locked).

    The probe runs INSIDE the daemon, NOT through `/chat/dispatch`,
    so it bypasses the dispatch mutex (the pause itself is what we're
    testing against). It does NOT touch the timeline (we don't want
    `chat.user` events for `probe-…` cluttering the cockpit).

    Cost: one ~10-token Claude Code invocation per paused key per
    hour. Negligible vs the cost of looping into a wall."""

    TICK_SECS = 60
    PROBE_PROMPT = (
        "This is an automated quota probe from the meshcore daemon. "
        "Reply with exactly the single word `pong` and nothing else. "
        "Do not use tools. Do not commit. End your turn immediately."
    )
    PROBE_PROMPT_TIMEOUT_SECS = 90  # subprocess wall-clock cap

    def __init__(self, daemon: Any) -> None:
        self.daemon = daemon
        self._stop = threading.Event()
        self._thread: Optional[threading.Thread] = None

    def start(self) -> None:
        if self._thread is not None:
            return
        self._thread = threading.Thread(target=self._loop, daemon=True)
        self._thread.start()
        _log(f"quota-prober: started (tick={self.TICK_SECS}s)")

    def stop(self) -> None:
        self._stop.set()

    def _loop(self) -> None:
        while not self._stop.wait(self.TICK_SECS):
            # FC-2 (daemon-centralized) — probe paused quota in EVERY project,
            # not just the default. Bind each project on this thread so
            # self.daemon.quota / _spawn_chat_turn resolve to it (and the probe
            # turn runs in the right cwd). Without this, a non-default project
            # stays paused forever after one rate-limit.
            reg = getattr(self.daemon, "_registry", None)
            pids = (
                [c.cluster.id for c in reg.built_contexts()]
                if reg is not None
                else [None]
            )
            for pid in pids:
                if self._stop.is_set():
                    break
                try:
                    if pid is not None:
                        self.daemon._set_req_project(pid)
                    due = self.daemon.quota.keys_due_for_probe()
                    for key in due:
                        if self._stop.is_set():
                            break
                        self._probe_one(key)
                except Exception as e:
                    _log(f"quota-prober: tick failed ({e})")
                finally:
                    if pid is not None:
                        self.daemon._clear_req_project()

    def _probe_one(self, key: str) -> None:
        # Resolve an agent_type for this key (any type whose manifest
        # matches; we use the first hit since they share a quota pool).
        agent_type = self._agent_type_for_key(key)
        probe_conv = f"probe-{key.replace('/', '-')}-{int(time.time())}"
        _log(f"quota-prober: probing {key} via {agent_type} (conv={probe_conv})")
        _debug_emit(
            "quota.probe.start",
            msg=f"probing {key}",
            conv=probe_conv,
            data={"quota_key": key, "agent_type": agent_type},
        )
        try:
            runner = self.daemon._spawn_chat_turn(
                probe_conv,
                self.PROBE_PROMPT,
                agent_type=agent_type,
                # No parent_conv on purpose — keeps the wake hook out.
            )
        except Exception as e:
            _log(f"quota-prober: spawn failed for {key}: {e}")
            self.daemon.quota.record_probe(key, probe_conv, "spawn-failed")
            return
        # Block until the subprocess ends or our timeout fires.
        runner.done.wait(timeout=self.PROBE_PROMPT_TIMEOUT_SECS)
        if not runner.done.is_set():
            _log(
                f"quota-prober: {key} timed out after {self.PROBE_PROMPT_TIMEOUT_SECS}s — cancelling"
            )
            try:
                runner.cancel()
            except Exception:
                pass
            self.daemon.quota.record_probe(key, probe_conv, "timeout")
            return
        # Classify the final.
        preview = (runner._cumulative_text or "").strip()
        exit_code = runner.proc.returncode if runner.proc else None
        outcome = self.daemon._classify_subagent_final(preview, exit_code)
        _debug_emit(
            "quota.probe.result",
            msg=f"probe {key} → {outcome}",
            conv=probe_conv,
            lvl=("info" if outcome == "success" else "warn"),
            data={
                "quota_key": key,
                "outcome": outcome,
                "exit": exit_code,
                "preview_head": preview[:200],
            },
        )
        # success → unpause (quota window has reset)
        # rate-limited → keep pause, bump consecutive counter (auto-extends)
        # no-commit / error → treat as inconclusive: leave pause as-is,
        #                     record probe so the operator can see history.
        if outcome == "success":
            self.daemon.quota.record_probe(key, probe_conv, "success")
            _log(f"quota-prober: {key} CLEARED (probe succeeded)")
        elif outcome == "rate-limited":
            # Extend the pause by another default cooldown.
            self.daemon.quota.pause(
                key,
                reason=f"probe still rate-limited ({probe_conv})",
            )
            self.daemon.quota.record_probe(key, probe_conv, "rate-limited")
            _log(f"quota-prober: {key} STILL LOCKED (probe rate-limited again)")
        else:
            self.daemon.quota.record_probe(key, probe_conv, outcome)
            _log(f"quota-prober: {key} probe inconclusive ({outcome})")

    def _agent_type_for_key(self, quota_key: str) -> str:
        """Pick any agent_type whose manifest maps to this quota_key.
        Falls back to 'custom' which is always present."""
        for t in AGENT_PROMPTS.keys():
            if _agent_manifest(t)["quota_key"] == quota_key:
                return t
        return "custom"


